-- ENGINEER_WRITTEN 2025년 제1회 기출 복원 — 100문항 일괄 적재
-- mock_exam: kind=PAST_EXAM, visibility=PUBLISHED, expert_verified=0
--
-- 재실행 안전성 — 동일 조합(exam_type + PAST_EXAM + 연도/회차) 정리 후 재삽입
DELETE FROM mock_exam
  WHERE exam_type = 'ENGINEER_WRITTEN'
    AND kind = 'PAST_EXAM'
    AND exam_year = 2025
    AND exam_round = 1;

SET @seq := (SELECT COALESCE(MAX(sequence), 0) + 1 FROM mock_exam WHERE exam_type = 'ENGINEER_WRITTEN');

INSERT INTO mock_exam
  (name, exam_type, sequence, visibility, expert_verified,
   kind, exam_year, exam_round, exam_date, created_at, updated_at)
VALUES
  ('정보처리기사 필기 2025년 1회 복원', 'ENGINEER_WRITTEN', @seq, 'PUBLISHED', 0,
   'PAST_EXAM', 2025, 1, '2025-02-07', NOW(6), NOW(6));

SET @mock_exam_id := LAST_INSERT_ID();

INSERT INTO question
  (subject_id, content, question_type, correct_option, explanation,
   topic, difficulty, mock_exam_id, display_order,
   verification_category, content_hash, created_at, updated_at)
VALUES
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '폭포수 모델의 한계를 극복하기 위해 고안된 모델로, 시제품을 먼저 만들어 최종 산출물을 미리 가늠하고 사용자 피드백을 설계에 반영하는 방식의 개발 방법론은?\n\n① 폭포수 모델\n② 프로토타입 모델\n③ 나선형 모델\n④ 애자일 모델', 'MCQ', 2, '정답: 2. 프로토타입 모델은 시제품을 통해 사용자의 평가를 받고 그 결과로 요구사항을 정교화하는 접근법이다.\n\n**오답 풀이**\n- 1번: 폭포수 모델은 단계가 한 방향으로 진행되는 순차적 개발 모델이다.\n- 2번: 프로토타입 모델은 시제품 기반 피드백을 핵심으로 한다.\n- 3번: 나선형 모델은 위험 분석을 반복하며 점진적으로 완성도를 높인다.\n- 4번: 애자일 모델은 짧은 반복 주기와 변화 수용을 강조하는 방법론이다.\n\n**보충 개념**\n프로토타입 모델은 요구사항이 명확하지 않은 초기 단계에서 사용자 의도를 빠르게 확인하는 데 효과적이다.',
   '프로토타입 모델', 2, @mock_exam_id, 1, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '나선형 프로세스는 개발 활동을 반복하며 점진적으로 시스템을 완성해 가는 방식이다. 다음은 나선형 프로세스의 주요 단계 흐름이다. 빈칸에 들어갈 단계로 알맞은 것은?\n\n**<보기>**\n계획 및 목표 설정 → ( 빈칸 ) → 공학적 개발 및 검증 → 고객 평가\n\n① 요구사항 분석\n② 위험 분석\n③ 테스트 설계\n④ 인터페이스 구현', 'MCQ', 2, '정답: 2. 나선형 모델의 반복 사이클에는 위험 분석 단계가 필수적으로 포함된다.\n\n**오답 풀이**\n- 1번: 요구사항 분석은 초기 활동에 해당하지만 나선형 모델의 정형화된 단계 명칭은 아니다.\n- 2번: 위험 분석은 나선형 모델을 특징짓는 핵심 단계이다.\n- 3번: 테스트 설계는 검증 활동에 가깝고 빈칸 위치의 단계가 아니다.\n- 4번: 인터페이스 구현은 구체적인 구현 활동 중 하나일 뿐이다.\n\n**보충 개념**\n나선형 모델은 계획 수립, 위험 분석, 개발과 검증, 고객 평가의 사이클을 반복적으로 수행한다.',
   '나선형 모델', 2, @mock_exam_id, 2, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '다음 중 애자일(Agile) 방법론에서 강조하는 가치로 보기 어려운 것은?\n\n① 소통과 협업\n② 절차와 문서화\n③ 변화에 대한 대응\n④ 고객과의 상호작용', 'MCQ', 2, '정답: 2. 애자일은 절차와 산출 문서보다 협업, 변화 수용, 고객과의 소통을 더 우선시한다.\n\n**오답 풀이**\n- 1번: 소통과 협업은 애자일이 강조하는 핵심 가치이다.\n- 2번: 절차와 문서화는 애자일에서 상대적으로 비중이 낮은 가치에 해당한다.\n- 3번: 변화에 대한 대응은 애자일의 대표 가치 중 하나이다.\n- 4번: 고객과의 상호작용 역시 애자일의 핵심 가치이다.\n\n**보충 개념**\n애자일 선언문은 프로세스나 도구보다 사람과 상호작용을, 방대한 문서보다 동작하는 소프트웨어를 더 가치 있게 여긴다.',
   '애자일', 1, @mock_exam_id, 3, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '다음 중 익스트림 프로그래밍(XP)의 다섯 가지 핵심 가치에 속하지 않는 것은?\n\n① 의사소통\n② 단순성\n③ 창조성\n④ 존중', 'MCQ', 3, '정답: 3. XP의 핵심 가치는 의사소통, 단순성, 피드백, 용기, 존중의 다섯 가지이다.\n\n**오답 풀이**\n- 1번: 의사소통은 XP가 정의한 핵심 가치이다.\n- 2번: 단순성은 XP의 핵심 가치이다.\n- 3번: 창조성은 XP의 다섯 가지 핵심 가치에 포함되지 않는다.\n- 4번: 존중은 XP의 핵심 가치이다.\n\n**보충 개념**\nXP는 고객 참여와 짧은 반복 주기 개발을 통해 코드 품질과 개발 생산성을 동시에 추구하는 애자일 방법론이다.',
   'XP', 1, @mock_exam_id, 4, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '다음 중 자료 흐름도(DFD)를 작성할 때 따라야 할 지침으로 보기 어려운 것은?\n\n① 단위 프로세스를 거친 데이터 흐름에는 새로운 이름을 부여한다.\n② 데이터 출력을 위해서는 반드시 입력이 있어야 한다.\n③ 최하위 프로세스는 소단위 명세서를 가져야 한다.\n④ 자료 흐름은 시간 순서를 고려하여 작성한다.', 'MCQ', 4, '정답: 4. DFD는 기능 관점의 데이터 이동을 표현하는 도구이며, 시간 순서를 시각화하는 것이 본래 목적이 아니다.\n\n**오답 풀이**\n- 1번: 프로세스를 통과해 변환된 데이터에는 의미를 분명히 할 수 있는 새로운 이름을 붙인다.\n- 2번: 출력 데이터가 있다면 그 근거가 되는 입력 데이터가 반드시 존재해야 한다.\n- 3번: 가장 하위 단계의 프로세스는 소단위 명세서로 상세히 풀어 기술한다.\n- 4번: 시간 흐름의 표현은 DFD의 주된 작성 지침이 아니다.\n\n**보충 개념**\nDFD는 처리(Process), 자료 흐름(Flow), 자료 저장소(Store), 외부 엔터티(Terminator)의 네 요소로 시스템을 표현한다.',
   'DFD', 2, @mock_exam_id, 5, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '다음 중 자료 흐름도(DFD)에서 데이터의 출발점이나 도착점 역할을 하는 외부 개체에 해당하는 구성 요소는?\n\n① 단말(Terminator)\n② 프로세스(Process)\n③ 자료 저장소(Data Store)\n④ 자료 흐름(Data Flow)', 'MCQ', 1, '정답: 1. 단말은 시스템 외부에 위치하면서 데이터를 공급하거나 결과를 받아가는 외부 엔터티이다.\n\n**오답 풀이**\n- 1번: 단말은 데이터의 시작 지점 또는 종착 지점을 담당한다.\n- 2번: 프로세스는 입력 데이터를 가공하여 출력 데이터로 만든다.\n- 3번: 자료 저장소는 데이터가 보관되는 위치를 나타낸다.\n- 4번: 자료 흐름은 데이터가 이동하는 경로를 표현한다.\n\n**보충 개념**\nDFD의 기본 네 요소는 프로세스, 자료 흐름, 자료 저장소, 단말(외부 엔터티)이다.',
   'DFD 구성요소', 1, @mock_exam_id, 6, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '다음 작업 네트워크에서 CPM(Critical Path Method)에 따른 프로젝트의 최소 완료 기간은?\n\n**<그림>**\n<svg xmlns="http://www.w3.org/2000/svg" width="680" height="260" viewBox="0 0 680 260" role="img" aria-label="작업 경로별 소요 기간 비교 그림">\n  <style>\n    .title{font-size:16px;font-family:Arial,sans-serif;font-weight:bold;fill:#111}\n    .label{font-size:14px;font-family:Arial,sans-serif;fill:#111}\n    .bar{fill:#e5e7eb;stroke:#555;stroke-width:1.5}\n    .axis{stroke:#777;stroke-width:1}\n  </style>\n  <text x="340" y="28" text-anchor="middle" class="title">작업 경로별 소요 기간</text>\n  <line x1="220" y1="220" x2="580" y2="220" class="axis"/>\n  <text x="220" y="240" text-anchor="middle" class="label">0</text>\n  <text x="460" y="240" text-anchor="middle" class="label">10</text>\n  <text x="580" y="240" text-anchor="middle" class="label">15일</text>\n  <text x="20" y="72" class="label">시작 → A → C → 종료</text>\n  <rect x="220" y="55" width="336" height="24" class="bar"/>\n  <text x="565" y="72" class="label">14일</text>\n  <text x="20" y="112" class="label">시작 → B → D → 종료</text>\n  <rect x="220" y="95" width="288" height="24" class="bar"/>\n  <text x="517" y="112" class="label">12일</text>\n  <text x="20" y="152" class="label">시작 → A → E → 종료</text>\n  <rect x="220" y="135" width="360" height="24" class="bar"/>\n  <text x="589" y="152" class="label">15일</text>\n  <text x="20" y="192" class="label">시작 → C → F → 종료</text>\n  <rect x="220" y="175" width="312" height="24" class="bar"/>\n  <text x="541" y="192" class="label">13일</text>\n</svg>\n\n**<작업 경로별 소요 기간>**\n- 시작 → A → C → 종료: 14일\n- 시작 → B → D → 종료: 12일\n- 시작 → A → E → 종료: 15일\n- 시작 → C → F → 종료: 13일\n\n① 14일\n② 12일\n③ 15일\n④ 13일', 'MCQ', 3, '정답: 3. CPM에서 프로젝트의 최소 완료 기간은 시작에서 종료에 이르는 모든 경로 중 가장 긴 경로의 소요 기간으로 결정된다. 제시된 경로에서는 `시작 → A → E → 종료`가 15일로 가장 길다.\n\n**오답 풀이**\n- 1번: 14일 경로는 임계 경로가 아니다.\n- 2번: 12일 경로는 임계 경로가 아니다.\n- 3번: 15일이 최장 경로이므로 CPM 기준 최소 완료 기간이 된다.\n- 4번: 13일 경로 역시 가장 긴 경로가 아니다.\n\n**보충 개념**\nCPM은 프로젝트의 최단 완료 시점을 산정하며, 임계 경로상의 작업이 지연되면 전체 일정도 함께 밀린다.',
   'CPM', 3, @mock_exam_id, 7, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '다음 중 소프트웨어 개발의 비용을 산정하기 위한 모델로 적절하지 않은 것은?\n\n① LOC 기반 비용 산정(라인 수 기반)\n② SWOT 분석 기반 비용 산정\n③ COCOMO 모델\n④ 기능 점수(Function Point) 기반 산정', 'MCQ', 2, '정답: 2. SWOT 분석은 강점, 약점, 기회, 위협을 점검하기 위한 경영 전략 도구이며 비용 산정 방법이 아니다.\n\n**오답 풀이**\n- 1번: LOC는 코드 라인 수를 토대로 비용을 추정하는 기법이다.\n- 2번: SWOT 분석은 비용 산정 모델로 분류되지 않는다.\n- 3번: COCOMO는 대표적인 소프트웨어 비용 산정 모델이다.\n- 4번: 기능 점수 산정은 시스템의 기능 규모를 척도로 비용을 추정한다.\n\n**보충 개념**\n대표적인 비용 산정 기법으로는 LOC, 기능 점수, COCOMO, Putnam 모델 등이 있다.',
   '비용 산정', 1, @mock_exam_id, 8, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '다음 중 작성될 코드의 분량을 기준으로 개발 비용을 추정하는 방식은?\n\n① LOC(Line of Code)\n② FP(Function Point)\n③ PERT(Program Evaluation Review Technique)\n④ CPM(Critical Path Method)', 'MCQ', 1, '정답: 1. LOC는 작성해야 할 소프트웨어의 코드 라인 수를 토대로 비용을 추정하는 기법이다.\n\n**오답 풀이**\n- 1번: LOC는 코드 라인 수를 척도로 삼는다.\n- 2번: FP는 시스템의 기능 규모를 척도로 사용한다.\n- 3번: PERT는 일정 추정과 관리에 활용되는 기법이다.\n- 4번: CPM은 임계 경로를 분석해 일정을 관리하는 기법이다.\n\n**보충 개념**\nLOC는 직관적이라는 장점이 있지만, 사용 언어와 개발자 숙련도에 따라 결과 편차가 큰 단점도 있다.',
   'LOC', 1, @mock_exam_id, 9, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '다음 중 CASE 도구의 특징으로 보기 어려운 것은?\n\n① 소프트웨어 개발 전 과정을 자동화한다.\n② 품질 향상과 생산성 향상에 기여한다.\n③ 유지보수 비용 절감에 도움이 된다.\n④ 개발 기간을 늘려 더 높은 품질을 보인다.', 'MCQ', 4, '정답: 4. CASE 도구는 개발 기간 단축과 품질 향상을 동시에 추구하며, 일부러 기간을 늘리는 것이 목적이 아니다.\n\n**오답 풀이**\n- 1번: CASE 도구는 개발 활동의 자동화를 지원한다.\n- 2번: 생산성 향상과 품질 향상에 기여한다.\n- 3번: 표준화와 문서화를 통해 유지보수 부담을 줄여 준다.\n- 4번: 개발 기간 연장이 CASE 도구의 본질적 특징은 아니다.\n\n**보충 개념**\nCASE 도구는 요구분석, 설계, 구현, 테스트 등 SW 개발 활동 전반을 지원하는 자동화 도구이다.',
   'CASE', 2, @mock_exam_id, 10, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '다음 중 데이터베이스와 연동하여 데이터의 저장과 검색을 처리하는 미들웨어는?\n\n① MOM\n② DBMS\n③ ORB\n④ WAS', 'MCQ', 2, '정답: 2. DBMS는 데이터베이스 관리를 담당하며 데이터의 저장, 조회, 갱신을 지원한다.\n\n**오답 풀이**\n- 1번: MOM은 메시지 전달 기반의 통신을 지원하는 미들웨어이다.\n- 2번: DBMS는 데이터베이스 관리 시스템이다.\n- 3번: ORB는 객체 간 통신을 매개하는 미들웨어이다.\n- 4번: WAS는 웹 애플리케이션이 동작하는 실행 환경을 제공한다.\n\n**보충 개념**\n미들웨어는 이기종 시스템이나 애플리케이션 사이의 통신과 데이터 교환을 매개하는 역할을 한다.',
   '미들웨어', 1, @mock_exam_id, 11, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '다음 중 요구사항 분석 활동의 특징으로 보기 어려운 것은?\n\n① 개발된 소프트웨어의 최종 성능을 보장한다.\n② 이해관계자의 요구사항을 도출하고 명확하게 정리한다.\n③ 요구사항의 충돌을 해결하고 우선순위를 부여한다.\n④ 요구사항 변경이 전체 개발에 영향을 줄 수 있음을 고려한다.', 'MCQ', 1, '정답: 1. 요구사항 분석은 개발 후 성능을 직접 보장하는 활동이 아니라, 요구사항을 식별하고 명확히 다듬는 활동이다.\n\n**오답 풀이**\n- 1번: 최종 성능 보장은 요구사항 분석 단계의 직접적 목적이 아니다.\n- 2번: 요구사항을 발굴하고 정리하는 것이 핵심 활동이다.\n- 3번: 충돌 조정과 우선순위 결정도 분석 활동에 포함된다.\n- 4번: 요구사항 변경이 가져올 영향을 평가하는 일도 중요하다.\n\n**보충 개념**\n요구사항 분석은 개발 범위와 목표를 명확히 정의하는 초기 핵심 단계이다.',
   '요구사항 분석', 2, @mock_exam_id, 12, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '다음 중 UML 상태 다이어그램에서 객체가 가지는 상태를 표현하는 구성 요소는?\n\n① Actor\n② Message\n③ State\n④ Usecase', 'MCQ', 3, '정답: 3. 상태 다이어그램에서 객체가 특정 시점에 갖는 속성이나 조건은 State로 표현된다.\n\n**오답 풀이**\n- 1번: Actor는 시스템 외부에서 시스템과 상호작용하는 주체이다.\n- 2번: Message는 객체 사이의 호출 또는 신호를 의미한다.\n- 3번: State는 객체의 상태를 나타낸다.\n- 4번: Usecase는 사용자의 기능 요구를 표현한다.\n\n**보충 개념**\n상태 다이어그램은 상태, 전이(Transition), 이벤트 등을 활용하여 객체의 동적 변화 과정을 시각화한다.',
   '상태 다이어그램', 1, @mock_exam_id, 13, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '다음 중 UML 활동(Activity) 다이어그램에 대한 설명으로 가장 적절한 것은?\n\n① 시스템이나 객체가 수행하는 작업의 흐름을 순서대로 표현한 다이어그램\n② 객체 간의 관계와 속성을 표현한 다이어그램\n③ 시스템 외부 사용자와 요구를 표현한 다이어그램\n④ 객체의 상태 변화 과정을 시간 흐름에 따라 표현한 다이어그램', 'MCQ', 1, '정답: 1. 활동 다이어그램은 시스템이나 객체가 수행하는 작업의 진행 순서를 표현한다.\n\n**오답 풀이**\n- 1번: 활동 다이어그램에 부합하는 설명이다.\n- 2번: 클래스 다이어그램에 해당하는 설명이다.\n- 3번: 유스케이스 다이어그램에 해당하는 설명이다.\n- 4번: 상태 다이어그램에 해당하는 설명이다.\n\n**보충 개념**\n활동 다이어그램은 업무 절차, 제어 흐름, 병렬 작업 흐름 등을 시각화하는 데 자주 활용된다.',
   '활동 다이어그램', 1, @mock_exam_id, 14, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '다음 중 터치 제스처의 종류로 보기 어려운 것은?\n\n① 더블탭(Double Tap)\n② 스와이프(Swipe)\n③ 핀치(Pinch)\n④ 롤오버(Rollover)', 'MCQ', 4, '정답: 4. 롤오버는 마우스 포인터를 객체 위에 올렸을 때 발생하는 마우스 이벤트로, 터치 제스처에 해당하지 않는다.\n\n**오답 풀이**\n- 1번: 더블탭은 화면을 두 번 두드리는 터치 제스처이다.\n- 2번: 스와이프는 화면을 쓸어 넘기는 터치 제스처이다.\n- 3번: 핀치는 두 손가락으로 확대·축소하는 터치 제스처이다.\n- 4번: 롤오버는 마우스 기반 입력 동작에 가깝다.\n\n**보충 개념**\n주요 터치 제스처에는 탭, 더블탭, 스와이프, 핀치, 드래그, 플릭 등이 있다.',
   'UI 제스처', 1, @mock_exam_id, 15, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '다음 중 기존 소프트웨어의 소스 코드를 분석해 설계 정보나 데이터 구조를 다시 도출해 내는 작업은?\n\n① 유스케이스\n② 이식\n③ 역공학\n④ 통합', 'MCQ', 3, '정답: 3. 기존 시스템의 코드를 해석해 설계 정보와 구조를 재구성하는 작업을 역공학이라 한다.\n\n**오답 풀이**\n- 1번: 유스케이스는 사용자의 기능 요구를 표현하는 모델 요소이다.\n- 2번: 이식은 소프트웨어를 다른 환경에서도 동작 가능하도록 옮기는 작업이다.\n- 3번: 역공학은 기존 코드에서 설계 정보를 추출하는 활동이다.\n- 4번: 통합은 여러 구성 요소를 하나로 결합하는 작업이다.\n\n**보충 개념**\n역공학은 유지보수나 재공학을 진행하기 전에 기존 시스템을 이해하기 위한 수단으로 활용된다.',
   '역공학', 1, @mock_exam_id, 16, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '다음 중 서브시스템들이 데이터를 차례대로 처리하면서 그 결과를 다음 서브시스템으로 넘기는 형태의 소프트웨어 아키텍처 패턴은?\n\n① 클라이언트-서버(Client-Server)\n② 브로커(Broker)\n③ 이벤트-버스(Event-Bus)\n④ 파이프-필터(Pipe-Filter)', 'MCQ', 4, '정답: 4. 파이프-필터 패턴은 각 필터가 데이터를 가공한 뒤 파이프를 통해 다음 필터로 넘기는 구조이다.\n\n**오답 풀이**\n- 1번: 클라이언트-서버는 요청을 보내는 측과 응답을 제공하는 측을 분리한 구조이다.\n- 2번: 브로커는 분산 객체 간의 요청을 중개하는 역할을 한다.\n- 3번: 이벤트-버스는 이벤트의 발행과 구독에 기반해 동작한다.\n- 4번: 파이프-필터는 순차적인 데이터 처리에 잘 어울린다.\n\n**보충 개념**\n파이프-필터 패턴은 컴파일러 단계, 데이터 변환 파이프라인, 스트림 처리 시스템에서 자주 활용된다.',
   '파이프-필터 패턴', 2, @mock_exam_id, 17, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '다음 중 EAI(Enterprise Application Integration) 구축 방식으로 보기 어려운 것은?\n\n① 데이터 스포크\n② 포인트 투 포인트\n③ 허브 앤 스포크\n④ 메시지 버스', 'MCQ', 1, '정답: 1. EAI의 대표적인 구축 방식으로는 포인트 투 포인트, 허브 앤 스포크, 메시지 버스, 하이브리드 방식이 있다.\n\n**오답 풀이**\n- 1번: 데이터 스포크는 EAI의 표준 구축 방식 명칭이 아니다.\n- 2번: 포인트 투 포인트는 두 시스템을 1:1로 직접 연결하는 방식이다.\n- 3번: 허브 앤 스포크는 중앙 허브를 매개로 시스템들을 연결한다.\n- 4번: 메시지 버스는 공통 메시지 버스를 통해 시스템 간을 연동한다.\n\n**보충 개념**\nEAI는 기업 내 다양한 애플리케이션을 통합해 데이터와 업무 프로세스를 일관되게 연계한다.',
   'EAI', 2, @mock_exam_id, 18, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '다음 중 한 모듈 안에서 구성 요소들이 서로 얼마나 긴밀하게 관련되어 있는지를 나타내는 척도는?\n\n① 결합도(Coupling)\n② 응집도(Cohesion)\n③ 복잡도(Complexity)\n④ 가용성(Availability)', 'MCQ', 2, '정답: 2. 모듈 내부 요소들이 서로 얼마나 밀접하게 관련되어 있는지를 나타내는 척도가 응집도이다.\n\n**오답 풀이**\n- 1번: 결합도는 서로 다른 모듈 간의 의존 정도를 의미한다.\n- 2번: 응집도는 모듈 내부 구성 요소 간의 관련 정도이다.\n- 3번: 복잡도는 시스템이나 코드의 복잡한 정도를 가리킨다.\n- 4번: 가용성은 시스템을 정상적으로 사용할 수 있는 정도를 의미한다.\n\n**보충 개념**\n바람직한 설계는 모듈의 응집도는 높이고 결합도는 낮추는 방향을 지향한다.',
   '응집도', 1, @mock_exam_id, 19, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '다음 중 모듈 간 결합도의 종류로 보기 어려운 것은?\n\n① 데이터 결합도(Data Coupling)\n② 스탬프 결합도(Stamp Coupling)\n③ 제어 결합도(Control Coupling)\n④ 프로세스 결합도(Process Coupling)', 'MCQ', 4, '정답: 4. 프로세스 결합도는 모듈 결합도의 표준 분류에 포함되지 않는 명칭이다.\n\n**오답 풀이**\n- 1번: 데이터 결합도는 필요한 자료만 인자로 주고받는 결합이다.\n- 2번: 스탬프 결합도는 자료 구조 전체를 인자로 전달할 때 발생한다.\n- 3번: 제어 결합도는 제어 정보를 전달해 다른 모듈의 흐름을 좌우한다.\n- 4번: 프로세스 결합도는 표준적인 결합도 분류에 포함되지 않는다.\n\n**보충 개념**\n결합도는 일반적으로 자료, 스탬프, 제어, 외부, 공통, 내용 결합도로 구분된다.',
   '결합도', 2, @mock_exam_id, 20, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '다음 중 형상 관리의 주요 활동으로 보기 어려운 것은?\n\n① 품질 보증(Quality Assurance)\n② 형상 식별(Configuration Identification)\n③ 형상 통제(Configuration Control)\n④ 형상 감사(Configuration Audit)', 'MCQ', 1, '정답: 1. 형상 관리의 주요 활동은 형상 식별, 형상 통제, 형상 감사, 형상 상태 보고이다.\n\n**오답 풀이**\n- 1번: 품질 보증은 형상 관리의 직접적인 구성 활동이라기보다 별개의 품질 활동에 가깝다.\n- 2번: 형상 식별은 관리 대상이 되는 산출물을 식별하는 활동이다.\n- 3번: 형상 통제는 변경 요청을 검토하고 승인·관리하는 활동이다.\n- 4번: 형상 감사는 형상 항목이 적절히 관리되었는지를 점검하는 활동이다.\n\n**보충 개념**\n형상 관리는 소프트웨어 산출물의 변경 이력과 버전을 체계적으로 통제하는 활동이다.',
   '형상 관리', 2, @mock_exam_id, 21, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '다음 중 WAS(Web Application Server)에 관한 설명으로 옳지 않은 것은?\n\n① HTTP 세션을 관리하고 동적 콘텐츠를 생성하는 서버이다.\n② 클라이언트와 서버 간 데이터베이스를 직접 연결하는 역할만 수행한다.\n③ 웹 서버와 데이터베이스 서버 사이에서 비즈니스 로직을 처리한다.\n④ JSP, Servlet과 같은 웹 애플리케이션을 실행한다.', 'MCQ', 2, '정답: 2. WAS는 단순히 클라이언트와 DB를 직접 연결만 하는 것이 아니라, 동적 페이지 생성, 세션 처리, 트랜잭션 관리 등 다양한 기능을 수행한다.\n\n**오답 풀이**\n- 1번: WAS는 동적 콘텐츠를 생성하고 세션을 관리한다.\n- 2번: DB 직접 연결만 한다는 설명은 적절하지 않다.\n- 3번: 웹 서버와 DB 사이에서 비즈니스 로직을 처리한다.\n- 4번: JSP와 Servlet 같은 웹 애플리케이션 실행을 지원한다.\n\n**보충 개념**\nWAS는 웹 애플리케이션의 실행 환경을 제공하며 웹 서버와 연동되어 동작한다.',
   'WAS', 2, @mock_exam_id, 22, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '다음 중 소스 코드 정적 분석에 사용되는 도구로 보기 어려운 것은?\n\n① SonarQube\n② cppcheck\n③ Selenium\n④ PMD', 'MCQ', 3, '정답: 3. Selenium은 웹 애플리케이션의 동작을 자동으로 테스트하는 도구이며 정적 분석 도구가 아니다.\n\n**오답 풀이**\n- 1번: SonarQube는 대표적인 정적 코드 분석 도구이다.\n- 2번: cppcheck는 C/C++ 코드를 위한 정적 분석 도구이다.\n- 3번: Selenium은 웹 UI 테스트 자동화 도구로 분류된다.\n- 4번: PMD는 자바 등을 대상으로 한 정적 분석 도구이다.\n\n**보충 개념**\n정적 분석은 프로그램을 실행하지 않고 코드의 결함, 규칙 위반, 품질 문제를 점검하는 방식이다.',
   '정적 분석', 1, @mock_exam_id, 23, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '다음 중 DRM(Digital Rights Management)을 구성하는 기술 요소로 보기 어려운 것은?\n\n① 암호화(Encryption)\n② 키 관리(Key Management)\n③ 정책 관리(Policy Management)\n④ 가상화 기술(Virtualization Technology)', 'MCQ', 4, '정답: 4. 가상화 기술은 서버나 저장 자원을 추상화하는 기반 기술이며 DRM과 직접적인 관련은 없다.\n\n**오답 풀이**\n- 1번: 암호화는 콘텐츠 보호의 핵심 기술이다.\n- 2번: 키 관리는 암호화에 사용되는 키를 안전하게 관리하는 DRM 요소이다.\n- 3번: 정책 관리는 콘텐츠 이용 조건과 권한을 통제한다.\n- 4번: 가상화는 DRM 구성 기술로 보기 어렵다.\n\n**보충 개념**\nDRM은 디지털 콘텐츠의 무단 복제와 불법 사용을 막기 위한 종합 기술이다.',
   'DRM', 1, @mock_exam_id, 24, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '다음 중 인터페이스 구현 검증 도구로 보기 어려운 것은?\n\n① Git\n② JUnit\n③ STAF\n④ FitNesse', 'MCQ', 1, '정답: 1. Git은 소스 코드의 버전을 관리하는 형상 관리 도구이며, 인터페이스 구현 검증 도구로 분류되지 않는다.\n\n**오답 풀이**\n- 1번: Git은 버전 관리 도구이므로 인터페이스 검증 도구의 범주에 들지 않는다.\n- 2번: JUnit은 xUnit 계열 테스트 프레임워크로 인터페이스 검증에도 활용된다.\n- 3번: STAF는 테스트 자동화 프레임워크로 인터페이스 검증에 사용된다.\n- 4번: FitNesse는 웹 기반의 테스트 케이스 작성과 실행을 지원하는 검증 도구이다.\n\n**보충 개념**\n인터페이스 구현 검증 도구로는 xUnit 계열, STAF, FitNesse, NTAF, Selenium 등이 자주 언급된다.',
   '인터페이스 검증', 2, @mock_exam_id, 25, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '다음 중 정형 기술 검토(FTR, Formal Technical Review)의 원칙으로 보기 어려운 것은?\n\n① 검토할 제품에 대한 체크리스트를 개발한다.\n② 제품 검토 외에 해결책과 개선책을 논의한다.\n③ 검토 과정과 결과를 재검토한다.\n④ 사전 준비를 강화하고 작성한 메모를 공유한다.', 'MCQ', 2, '정답: 2. FTR은 산출물의 결함을 발견하고 품질을 확인하는 데 집중하며, 해결책 논의에 시간을 할애하지 않도록 권장한다.\n\n**오답 풀이**\n- 1번: 체크리스트를 활용하면 검토 품질을 높일 수 있다.\n- 2번: 해결책과 개선책 토론에 집중하는 것은 FTR 원칙과 어긋난다.\n- 3번: 검토 결과를 다시 검토하는 절차는 적절하다.\n- 4번: 충분한 사전 준비와 메모 공유는 검토 효과를 높여 준다.\n\n**보충 개념**\nFTR은 논쟁에 시간을 쓰기보다 결함 발견에 집중하며, 검토 대상 산출물 자체에 초점을 맞춘다.',
   'FTR', 2, @mock_exam_id, 26, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '다음 중 선형 자료 구조에 속하지 않는 것은?\n\n① 스택(Stack)\n② 큐(Queue)\n③ 트리(Tree)\n④ 데크(Deque)', 'MCQ', 3, '정답: 3. 트리는 노드들이 계층적으로 연결된 비선형 자료 구조이다.\n\n**오답 풀이**\n- 1번: 스택은 자료가 일렬로 쌓이는 선형 자료 구조이다.\n- 2번: 큐는 일렬로 자료가 늘어선 선형 자료 구조이다.\n- 3번: 트리는 비선형 자료 구조에 해당한다.\n- 4번: 데크는 양쪽 끝에서 삽입과 삭제가 가능한 선형 자료 구조이다.\n\n**보충 개념**\n선형 자료 구조는 자료가 일렬로 연결되며, 비선형 자료 구조는 계층 구조나 그래프 형태를 갖는다.',
   '자료 구조', 1, @mock_exam_id, 27, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '다음 중 스택(Stack)의 활용 사례로 보기 어려운 것은?\n\n① 함수 호출 관리\n② 후위 표기식 계산\n③ 깊이 우선 탐색(DFS)\n④ 선입선출 방식의 작업 대기열 처리', 'MCQ', 4, '정답: 4. 선입선출 방식의 작업 대기열을 처리하는 것은 큐(Queue)의 대표적인 활용 사례이다.\n\n**오답 풀이**\n- 1번: 함수 호출 관리는 콜 스택을 통해 구현된다.\n- 2번: 후위 표기식 계산은 스택을 활용해 처리한다.\n- 3번: DFS는 스택 구조를 이용해 구현할 수 있다.\n- 4번: FIFO 방식의 작업 대기열은 큐의 활용 사례이다.\n\n**보충 개념**\n스택은 LIFO(후입선출), 큐는 FIFO(선입선출) 구조를 따른다.',
   '스택', 1, @mock_exam_id, 28, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '다음 중 시간 복잡도 O(1)에 대한 설명으로 가장 알맞은 것은?\n\n① 입력 데이터 크기에 관계없이 일정한 횟수의 연산이 수행된다.\n② 입력 데이터 크기에 비례하여 연산 횟수가 증가한다.\n③ 입력 데이터 크기의 제곱에 비례하여 연산 횟수가 증가한다.\n④ 입력 데이터 크기에 따라 연산 횟수가 로그 형태로 증가한다.', 'MCQ', 1, '정답: 1. O(1)은 입력 크기에 관계없이 항상 일정한 시간 또는 연산 횟수를 갖는 상수 시간 복잡도이다.\n\n**오답 풀이**\n- 1번: O(1)에 부합하는 설명이다.\n- 2번: 입력 크기에 비례하는 것은 O(n)이다.\n- 3번: 입력 크기의 제곱에 비례하는 것은 O(n²)이다.\n- 4번: 로그적으로 증가하는 것은 O(log n)이다.\n\n**보충 개념**\n배열의 인덱스 접근처럼 입력 크기와 무관하게 한 번에 처리되는 연산은 O(1)에 해당한다.',
   '시간 복잡도', 1, @mock_exam_id, 29, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '다음 중 평균 시간 복잡도가 O(N²)이 아닌 정렬 방법은?\n\n① 선택 정렬(Selection Sort)\n② 버블 정렬(Bubble Sort)\n③ 삽입 정렬(Insertion Sort)\n④ 퀵 정렬(Quick Sort)', 'MCQ', 4, '정답: 4. 퀵 정렬의 평균 시간 복잡도는 O(n log n)이다.\n\n**오답 풀이**\n- 1번: 선택 정렬의 평균 시간 복잡도는 O(n²)이다.\n- 2번: 버블 정렬의 평균 시간 복잡도는 O(n²)이다.\n- 3번: 삽입 정렬의 평균 시간 복잡도는 O(n²)이다.\n- 4번: 퀵 정렬의 평균 시간 복잡도는 O(n log n)이다.\n\n**보충 개념**\n퀵 정렬은 최악의 경우 O(n²)까지 떨어지지만, 평균적으로는 O(n log n)의 성능을 보인다.',
   '정렬', 2, @mock_exam_id, 30, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '다음 중 블랙박스 테스트 기법으로 보기 어려운 것은?\n\n① 동등 분할 테스트\n② 경계값 분석\n③ 제어 구조 검사\n④ 원인-효과 그래프', 'MCQ', 3, '정답: 3. 제어 구조 검사는 코드 내부 구조를 기반으로 하는 화이트박스 테스트 기법이다.\n\n**오답 풀이**\n- 1번: 동등 분할 테스트는 블랙박스 테스트 기법이다.\n- 2번: 경계값 분석은 블랙박스 테스트 기법이다.\n- 3번: 제어 구조 검사는 내부 구조 기반 테스트에 해당한다.\n- 4번: 원인-효과 그래프는 블랙박스 테스트 기법이다.\n\n**보충 개념**\n블랙박스 테스트는 내부 구현을 보지 않고 입력과 출력의 관점에서 시스템을 검증한다.',
   '블랙박스 테스트', 1, @mock_exam_id, 31, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '다음 중 화이트박스 테스트 기법으로 보기 어려운 것은?\n\n① 기초 경로 테스트\n② 조건 커버리지 테스트\n③ 결정 커버리지 테스트\n④ 유스케이스 다이어그램 테스트', 'MCQ', 4, '정답: 4. 유스케이스 다이어그램 기반 테스트는 코드 내부 구조 분석을 토대로 하는 화이트박스 테스트 기법이 아니다.\n\n**오답 풀이**\n- 1번: 기초 경로 테스트는 화이트박스 테스트 기법이다.\n- 2번: 조건 커버리지는 내부 조건식을 기준으로 검사한다.\n- 3번: 결정 커버리지는 분기 결과를 기준으로 검사한다.\n- 4번: 유스케이스 기반 테스트는 코드 내부 구조 검사가 주가 아니다.\n\n**보충 개념**\n화이트박스 테스트는 코드의 논리 구조, 경로, 조건, 분기 등을 분석하는 테스트 방식이다.',
   '화이트박스 테스트', 1, @mock_exam_id, 32, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '다음 중 알파 테스트에 대한 설명으로 가장 알맞은 것은?\n\n① 개발자가 개발 장소에서 사용자의 참여 하에 수행하는 테스트\n② 일반 사용자들이 다양한 환경에서 자유롭게 수행하는 테스트\n③ 시스템 전체 기능을 통합한 후 최종적으로 수행하는 테스트\n④ 제품의 품질 인증을 위해 외부 기관에서 수행하는 테스트', 'MCQ', 1, '정답: 1. 알파 테스트는 개발 환경에서 일부 사용자가 참여해 수행하는 인수 단계의 테스트이다.\n\n**오답 풀이**\n- 1번: 알파 테스트의 정의에 부합하는 설명이다.\n- 2번: 다양한 환경에서 일반 사용자들이 수행하는 것은 베타 테스트에 해당한다.\n- 3번: 통합 후 최종 수행하는 것은 시스템 테스트에 가깝다.\n- 4번: 외부 인증 기관이 수행하는 것은 품질 인증 테스트와 관련된다.\n\n**보충 개념**\n알파 테스트는 개발사 내부 또는 개발 장소에서 제한된 사용자가 참여해 진행한다.',
   '알파 테스트', 1, @mock_exam_id, 33, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '다음 중 소스코드 인스펙션에서 정의하는 오류 종류로 보기 어려운 것은?\n\n① DA\n② FN\n③ SN\n④ LO', 'MCQ', 3, '정답: 3. SN은 소스코드 인스펙션의 표준 오류 분류로 보기 어렵다.\n\n**오답 풀이**\n- 1번: DA는 데이터 관련 오류 유형으로 분류된다.\n- 2번: FN은 기능 관련 오류 유형으로 분류된다.\n- 3번: SN은 표준 오류 분류 명칭에 해당하지 않는다.\n- 4번: LO는 논리 관련 오류 유형으로 분류된다.\n\n**보충 개념**\n소스코드 인스펙션에서는 기능, 데이터, 논리, 성능, 문서 등 여러 관점에서 오류를 분류해 점검한다.',
   '코드 인스펙션', 2, @mock_exam_id, 34, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '다음 중 이진트리에서 사용하는 기본 용어로 보기 어려운 것은?\n\n① 루트 노드\n② 단말 노드\n③ 스택 노드\n④ 내부 노드', 'MCQ', 3, '정답: 3. 스택 노드는 스택 자료구조에서 등장하는 표현이며 이진트리의 용어로 분류되지 않는다.\n\n**오답 풀이**\n- 1번: 루트 노드는 트리 구조의 최상위 노드를 가리킨다.\n- 2번: 단말 노드는 자식 노드가 없는 노드를 의미한다.\n- 3번: 스택 노드는 이진트리의 기본 용어가 아니다.\n- 4번: 내부 노드는 자식이 존재하는 노드를 가리킨다.\n\n**보충 개념**\n트리에서 자주 사용되는 용어로는 루트, 부모, 자식, 형제, 단말, 내부 노드 등이 있다.',
   '이진트리', 1, @mock_exam_id, 35, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '다음 중 소스 코드 최적화 기법으로 보기 어려운 것은?\n\n① 코드 가독성 향상\n② 코드 중복 제거\n③ 하드코딩 증가\n④ 데이터 추상화 적용', 'MCQ', 3, '정답: 3. 하드코딩을 늘리면 유지보수성과 확장성이 모두 떨어지므로 최적화 기법이라 할 수 없다.\n\n**오답 풀이**\n- 1번: 코드 가독성을 높이면 유지보수가 수월해진다.\n- 2번: 중복 코드를 제거하면 변경 비용을 줄일 수 있다.\n- 3번: 하드코딩 증가는 오히려 코드 품질을 떨어뜨린다.\n- 4번: 데이터 추상화 적용은 구조 개선에 도움이 된다.\n\n**보충 개념**\n소스 코드 최적화는 가독성, 유지보수성, 실행 효율, 중복 제거 같은 측면을 함께 고려한다.',
   '코드 최적화', 1, @mock_exam_id, 36, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '다음 중 소프트웨어 유지보수의 유형으로 보기 어려운 것은?\n\n① 회귀 보수\n② 하자 보수\n③ 완전 보수\n④ 예방 보수', 'MCQ', 1, '정답: 1. 회귀 보수는 표준적으로 분류되는 유지보수 유형이 아니다.\n\n**오답 풀이**\n- 1번: 회귀 보수는 일반적인 유지보수 유형 분류에 포함되지 않는다.\n- 2번: 하자 보수는 결함을 고치는 수정 보수와 유사한 개념으로 볼 수 있다.\n- 3번: 완전 보수는 기능 개선과 성능 향상을 목적으로 한다.\n- 4번: 예방 보수는 장차 발생할 문제를 미리 방지하기 위한 활동이다.\n\n**보충 개념**\n유지보수는 일반적으로 수정, 적응, 완전, 예방 보수의 네 가지로 구분된다.',
   '유지보수', 2, @mock_exam_id, 37, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '다음 중 애플리케이션 성능 지표에 관한 설명으로 옳지 않은 것은?\n\n① 처리량은 단위 시간당 시스템이 처리한 작업량을 의미한다.\n② 응답 시간은 요청이 완료될 때까지 걸린 시간을 의미한다.\n③ 경과 시간은 요청 후 응답이 완료되기까지 사용자가 느끼는 주관적 시간이다.\n④ 자원 사용률은 CPU, 메모리 등 시스템 자원이 사용된 비율을 의미한다.', 'MCQ', 3, '정답: 3. 경과 시간은 작업이 시작된 시점부터 끝난 시점까지의 객관적인 실제 소요 시간을 의미한다.\n\n**오답 풀이**\n- 1번: 처리량은 단위 시간당 처리한 작업의 양이다.\n- 2번: 응답 시간은 요청이 완료될 때까지 걸린 시간이다.\n- 3번: 경과 시간을 사용자가 느끼는 주관적 시간으로 정의한 것은 적절하지 않다.\n- 4번: 자원 사용률은 CPU와 메모리 같은 자원이 얼마만큼 사용되었는지를 나타낸다.\n\n**보충 개념**\n주요 성능 지표에는 처리량, 응답 시간, 경과 시간, 자원 사용률 등이 있다.',
   '성능 지표', 2, @mock_exam_id, 38, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '다음 중 테스트 하네스(Test Harness)의 구성 요소로 보기 어려운 것은?\n\n① 드라이버(Driver)\n② 스텁(Stub)\n③ 목업(Mockup)\n④ 버퍼(Buffer)', 'MCQ', 4, '정답: 4. 버퍼는 데이터를 임시로 보관하는 메모리 공간이며 테스트 하네스의 표준 구성 요소가 아니다.\n\n**오답 풀이**\n- 1번: 드라이버는 하위 모듈을 호출해 주는 테스트 보조 모듈이다.\n- 2번: 스텁은 아직 구현되지 않은 하위 모듈을 대신해 주는 모듈이다.\n- 3번: 목업은 테스트에 사용할 가짜 객체나 화면을 의미한다.\n- 4번: 버퍼는 테스트 하네스 구성 요소로 보기 어렵다.\n\n**보충 개념**\n테스트 하네스는 드라이버, 스텁, 테스트 케이스, 테스트 데이터 등 테스트 실행을 보조하는 환경 전반을 포괄한다.',
   '테스트 하네스', 2, @mock_exam_id, 39, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '다음 중 소프트웨어 테스트 관련 용어에 대한 설명으로 옳지 않은 것은?\n\n① 오류(Error)는 소프트웨어 설계나 구현에서 사람에 의해 발생한 실수를 의미한다.\n② 결함(Defect)은 오류로 인해 발생한 소프트웨어 내부의 문제를 의미한다.\n③ 실패(Failure)는 결함이 실행되어 잘못된 결과를 초래한 현상을 의미한다.\n④ 테스트(Test)는 소프트웨어가 완벽하게 동작함을 증명하기 위한 과정이다.', 'MCQ', 4, '정답: 4. 테스트는 결함을 발견하기 위한 활동이며, 소프트웨어가 결함이 전혀 없음을 증명할 수 있는 절차가 아니다.\n\n**오답 풀이**\n- 1번: 오류는 사람의 실수에서 비롯되는 개념이다.\n- 2번: 결함은 오류가 산출물에 반영된 결과로 발생한 문제이다.\n- 3번: 실패는 결함이 실행되면서 잘못된 결과로 표면화된 현상이다.\n- 4번: 테스트만으로 소프트웨어의 완벽성을 증명할 수는 없다.\n\n**보충 개념**\n테스트는 결함의 존재를 보일 수 있을 뿐, 결함이 전혀 없음을 보장해 주지는 못한다.',
   '테스트 용어', 1, @mock_exam_id, 40, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '다음 중 데이터 정의어(DDL)에 해당하는 SQL 명령은?\n\n① CREATE\n② SELECT\n③ INSERT\n④ UPDATE', 'MCQ', 1, '정답: 1. CREATE는 데이터베이스 객체를 새로 만드는 DDL 명령이다.\n\n**오답 풀이**\n- 1번: CREATE는 DDL에 해당한다.\n- 2번: SELECT는 데이터를 조회하는 DML이다.\n- 3번: INSERT는 데이터를 삽입하는 DML이다.\n- 4번: UPDATE는 데이터를 수정하는 DML이다.\n\n**보충 개념**\nDDL의 대표 명령으로 CREATE, ALTER, DROP, TRUNCATE 등이 있다.',
   'DDL', 1, @mock_exam_id, 41, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '다음 중 릴레이션(Relation)의 특성으로 보기 어려운 것은?\n\n① 튜플 간 순서가 존재한다.\n② 속성 간 순서는 의미가 없다.\n③ 튜플은 유일해야 한다.\n④ 각 속성은 원자값만 가져야 한다.', 'MCQ', 1, '정답: 1. 릴레이션에서 튜플 사이의 순서는 의미를 갖지 않는다.\n\n**오답 풀이**\n- 1번: 튜플 간 순서가 존재한다는 설명은 옳지 않다.\n- 2번: 속성 간의 순서는 릴레이션에서 의미가 없다.\n- 3번: 튜플은 서로 중복되지 않아야 한다.\n- 4번: 각 속성은 더 이상 분해되지 않는 원자값을 가져야 한다.\n\n**보충 개념**\n릴레이션은 행을 튜플, 열을 속성으로 갖는 2차원 테이블 형태로 표현된다.',
   '릴레이션', 1, @mock_exam_id, 42, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '다음 중 데이터베이스 키(Key)에 관한 설명으로 보기 어려운 것은?\n\n① 튜플을 유일하게 식별할 수 있어야 한다.\n② 후보키는 유일성과 최소성을 모두 만족해야 한다.\n③ 기본키는 NULL 값을 가질 수 있다.\n④ 외래키는 다른 릴레이션의 기본키를 참조할 수 있다.', 'MCQ', 3, '정답: 3. 기본키는 개체 무결성을 만족해야 하므로 NULL 값을 가질 수 없다.\n\n**오답 풀이**\n- 1번: 키는 튜플을 식별하는 역할을 한다.\n- 2번: 후보키는 유일성과 최소성을 동시에 만족한다.\n- 3번: 기본키는 NULL을 가질 수 없다.\n- 4번: 외래키는 다른 릴레이션의 기본키를 참조할 수 있다.\n\n**보충 개념**\n기본키는 개체 무결성을 충족해야 하므로 중복도, NULL도 허용되지 않는다.',
   '키', 1, @mock_exam_id, 43, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '다음 중 데이터 모델의 표현 요소로 보기 어려운 것은?\n\n① 데이터 구조(Data Structure)\n② 데이터 연산(Operation)\n③ 데이터 제약조건(Constraint)\n④ 데이터 가상화(Virtualization)', 'MCQ', 4, '정답: 4. 데이터 모델의 표현 요소는 일반적으로 데이터 구조, 연산, 제약조건이며 데이터 가상화는 포함되지 않는다.\n\n**오답 풀이**\n- 1번: 데이터 구조는 데이터 모델의 표현 요소이다.\n- 2번: 데이터 연산은 데이터 모델의 표현 요소이다.\n- 3번: 데이터 제약조건은 데이터 모델의 표현 요소이다.\n- 4번: 데이터 가상화는 데이터 모델의 표현 요소로 분류되지 않는다.\n\n**보충 개념**\n데이터 모델은 데이터를 어떤 구조로 정의하고, 어떻게 다루며, 어떤 제약을 받게 할 것인지를 표현한다.',
   '데이터 모델', 1, @mock_exam_id, 44, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '다음 중 참조 무결성 제약조건의 특징으로 가장 알맞은 것은?\n\n① 외래키는 참조하는 기본키가 존재해야 한다.\n② 외래키는 항상 NULL 값을 가져야 한다.\n③ 기본키는 다른 테이블을 참조할 수 없다.\n④ 외래키는 무조건 고유(unique)해야 한다.', 'MCQ', 1, '정답: 1. 참조 무결성은 외래키 값이 참조 대상 릴레이션의 기본키와 일치하거나 NULL이어야 한다는 제약이다.\n\n**오답 풀이**\n- 1번: 외래키는 참조하는 기본키 값이 존재해야 한다.\n- 2번: 외래키가 항상 NULL이어야 하는 것은 아니다.\n- 3번: 기본키도 다른 테이블에서 참조될 수 있다.\n- 4번: 외래키는 반드시 고유해야 하는 것은 아니다.\n\n**보충 개념**\n참조 무결성은 릴레이션 간 관계의 일관성을 유지해 준다.',
   '참조 무결성', 2, @mock_exam_id, 45, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '다음 중 E-R 다이어그램(Entity-Relationship Diagram)의 기본 구성 요소로 보기 어려운 것은?\n\n① 개체(Entity)\n② 관계(Relationship)\n③ 속성(Attribute)\n④ 프로시저(Procedure)', 'MCQ', 4, '정답: 4. E-R 다이어그램의 기본 구성 요소는 개체, 관계, 속성이다.\n\n**오답 풀이**\n- 1번: 개체는 E-R 다이어그램의 핵심 구성 요소이다.\n- 2번: 관계는 개체들 사이의 연관성을 표현한다.\n- 3번: 속성은 개체나 관계가 갖는 특성을 표현한다.\n- 4번: 프로시저는 E-R 다이어그램의 기본 구성 요소가 아니다.\n\n**보충 개념**\nE-R 모델은 데이터 사이의 논리적 관계를 시각화하기 위한 모델이다.',
   'E-R 다이어그램', 1, @mock_exam_id, 46, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '다음 중 E-R 다이어그램의 특징으로 보기 어려운 것은?\n\n① 개체 간의 관계를 도형을 사용하여 표현한다.\n② 데이터베이스의 물리적 저장 구조를 상세히 설계한다.\n③ 업무의 데이터 구조를 명확히 시각화한다.\n④ 데이터 간의 논리적 구조를 중심으로 모델링한다.', 'MCQ', 2, '정답: 2. E-R 다이어그램은 데이터 간의 논리적 관계를 표현하는 모델이며, 물리적 저장 구조를 상세히 설계하기 위한 도구는 아니다.\n\n**오답 풀이**\n- 1번: E-R 다이어그램은 도형을 활용해 개체와 관계를 시각화한다.\n- 2번: 물리적 저장 구조의 상세 설계는 물리 데이터 모델링 단계에 가깝다.\n- 3번: 업무 데이터 구조를 한눈에 보여 줄 수 있다.\n- 4번: 논리적 구조 중심의 모델링 도구이다.\n\n**보충 개념**\nE-R 다이어그램은 개념적 데이터 모델링 단계에서 폭넓게 활용된다.',
   'E-R 모델', 2, @mock_exam_id, 47, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '다음 중 TCL 명령에 해당하지 않는 것은?\n\n① COMMIT\n② ROLLBACK\n③ SAVEPOINT\n④ REVOKE', 'MCQ', 4, '정답: 4. REVOKE는 권한을 회수하는 DCL 명령이다.\n\n**오답 풀이**\n- 1번: COMMIT은 TCL 명령이다.\n- 2번: ROLLBACK은 TCL 명령이다.\n- 3번: SAVEPOINT는 TCL 명령이다.\n- 4번: REVOKE는 DCL 명령에 해당한다.\n\n**보충 개념**\nTCL은 트랜잭션을 제어하는 명령으로 COMMIT, ROLLBACK, SAVEPOINT가 대표적이다.',
   'TCL', 1, @mock_exam_id, 48, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '다음 중 부여받은 권한을 다른 사용자에게 다시 부여할 수 있도록 허용하는 SQL 문장은?\n\n① GRANT SELECT ON 테이블명 TO 사용자 WITH GRANT OPTION\n② REVOKE SELECT ON 테이블명 FROM 사용자\n③ COMMIT SELECT ON 테이블명 TO 사용자 WITH GRANT OPTION\n④ ROLLBACK SELECT ON 테이블명 FROM 사용자', 'MCQ', 1, '정답: 1. WITH GRANT OPTION은 부여받은 권한을 다른 사용자에게 다시 부여할 수 있게 해 준다.\n\n**오답 풀이**\n- 1번: 권한 부여와 함께 재부여 권한까지 함께 제공한다.\n- 2번: REVOKE는 권한을 회수하는 명령이다.\n- 3번: COMMIT은 트랜잭션을 확정하는 명령이다.\n- 4번: ROLLBACK은 트랜잭션을 취소하는 명령이다.\n\n**보충 개념**\nGRANT는 권한 부여, REVOKE는 권한 회수에 사용되는 DCL 명령이다.',
   'GRANT', 2, @mock_exam_id, 49, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '다음 중 분산 데이터베이스의 특징으로 보기 어려운 것은?\n\n① 물리적으로 분산되어 있으나 논리적으로 통합되어 관리된다.\n② 각 지역 데이터베이스는 독립적으로 관리될 수 있다.\n③ 데이터베이스 간 통신은 필요하지 않다.\n④ 장애 발생 시 무결성과 신뢰성을 유지해야 한다.', 'MCQ', 3, '정답: 3. 분산 데이터베이스는 여러 사이트의 DB가 통신을 통해 연동되며, 통신 자체가 불필요한 것은 아니다.\n\n**오답 풀이**\n- 1번: 물리적으로는 분산되어 있어도 논리적으로는 하나의 데이터베이스처럼 관리된다.\n- 2번: 각 지역 DB는 독립적으로 운영될 수 있다.\n- 3번: DB 간 통신은 필수적이다.\n- 4번: 장애 상황에서도 데이터의 무결성과 신뢰성을 유지해야 한다.\n\n**보충 개념**\n분산 데이터베이스는 위치 투명성, 중복 투명성, 장애 투명성 등 다양한 투명성을 제공한다.',
   '분산 데이터베이스', 2, @mock_exam_id, 50, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '다음 중 분산 데이터베이스 시스템의 핵심 구성 요소로 보기 어려운 것은?\n\n① 통신 네트워크\n② 분산 DBMS\n③ 분산처리 처리기\n④ 데이터 웨어하우스', 'MCQ', 4, '정답: 4. 데이터 웨어하우스는 대규모 분석을 위한 통합 저장소이며 분산 데이터베이스 시스템의 핵심 구성 요소로 분류되지 않는다.\n\n**오답 풀이**\n- 1번: 통신 네트워크는 분산 시스템을 구성하는 필수 요소이다.\n- 2번: 분산 DBMS는 분산된 데이터를 관리한다.\n- 3번: 분산 처리기는 분산 처리를 수행하는 데 필요하다.\n- 4번: 데이터 웨어하우스는 분석용 통합 저장소이며 분산 DB 시스템의 핵심 구성 요소가 아니다.\n\n**보충 개념**\n분산 데이터베이스는 분산 처리기, 분산 DBMS, 통신 네트워크 등이 결합되어 동작한다.',
   '분산 데이터베이스', 2, @mock_exam_id, 51, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '다음 SQL 문장을 올바르게 해석한 것은?\n\n```sql\nSELECT customer_id, first_name, last_name\nFROM customers\nWHERE email IS NOT NULL;\n```\n\n① 이메일이 입력된 고객들의 ID, 이름, 성을 조회한다.\n② 이메일이 없는 고객들의 ID, 이름, 성을 조회한다.\n③ 모든 고객들의 ID, 이름, 성을 조회한다.\n④ 이메일이 NULL인 고객만을 조회한다.', 'MCQ', 1, '정답: 1. `IS NOT NULL`은 해당 열의 값이 NULL이 아닌 행을 선택하는 조건이다.\n\n**오답 풀이**\n- 1번: 이메일 값이 입력된 고객을 조회하는 의미이므로 옳다.\n- 2번: 이메일이 없는 고객을 조회하려면 `IS NULL` 조건을 사용한다.\n- 3번: WHERE 조건이 있으므로 모든 고객을 조회하지는 않는다.\n- 4번: `IS NOT NULL`은 NULL이 아닌 행을 의미한다.\n\n**보충 개념**\nSQL에서 NULL 값을 비교할 때는 `= NULL`이 아닌 `IS NULL` 또는 `IS NOT NULL`을 사용해야 한다.',
   'NULL 조건', 1, @mock_exam_id, 52, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '다음 중 병행제어(Concurrency Control)의 장점으로 보기 어려운 것은?\n\n① 데이터의 무결성을 유지할 수 있다.\n② 다수의 사용자가 동시에 데이터에 접근할 수 있다.\n③ 트랜잭션의 결과를 불일치 상태로 만든다.\n④ 시스템 자원의 활용도를 높일 수 있다.', 'MCQ', 3, '정답: 3. 병행제어는 트랜잭션의 일관성과 무결성을 보호하는 기법이다.\n\n**오답 풀이**\n- 1번: 병행제어는 데이터 무결성 유지에 기여한다.\n- 2번: 여러 사용자가 동시에 데이터에 접근하도록 지원한다.\n- 3번: 결과를 불일치 상태로 만드는 것은 병행제어의 목적이 아니다.\n- 4번: 시스템 자원 활용도를 높일 수 있다.\n\n**보충 개념**\n병행제어가 부재하면 갱신 손실, 모순성, 연쇄 복귀 같은 문제가 발생할 수 있다.',
   '병행제어', 2, @mock_exam_id, 53, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '다음 중 데이터베이스 뷰(View)의 특징으로 보기 어려운 것은?\n\n① 실제 데이터는 저장하지 않고 정의만 저장된다.\n② 보안상 장점에 활용될 수 있다.\n③ 수정 작업이 항상 자유롭고 쉽다.\n④ 복잡한 질의를 단순화할 수 있다.', 'MCQ', 3, '정답: 3. 뷰는 정의 방식에 따라 갱신 가능 여부가 달라지며 모든 뷰에서 자유롭게 수정할 수 있는 것은 아니다.\n\n**오답 풀이**\n- 1번: 일반적인 뷰는 실제 데이터를 저장하지 않고 정의만 저장한다.\n- 2번: 필요한 행이나 열만 노출함으로써 보안 향상에 활용된다.\n- 3번: 모든 뷰가 자유롭게 갱신 가능한 것은 아니다.\n- 4번: 복잡한 질의를 간결한 인터페이스로 제공할 수 있다.\n\n**보충 개념**\n뷰는 논리적인 가상 테이블이며 데이터 독립성과 보안성을 높이는 데 사용된다.',
   '뷰', 2, @mock_exam_id, 54, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '다음 중 트랜잭션의 ACID 특성에 포함되지 않는 것은?\n\n① Accessibility\n② Atomicity\n③ Consistency\n④ Durability', 'MCQ', 1, '정답: 1. ACID는 Atomicity, Consistency, Isolation, Durability를 의미하며 Accessibility는 포함되지 않는다.\n\n**오답 풀이**\n- 1번: Accessibility는 ACID에 속하지 않는 용어이다.\n- 2번: Atomicity는 원자성을 의미한다.\n- 3번: Consistency는 일관성을 의미한다.\n- 4번: Durability는 지속성을 의미한다.\n\n**보충 개념**\nACID는 트랜잭션의 안정성과 신뢰성을 보장하기 위한 핵심 특성이다.',
   'ACID', 1, @mock_exam_id, 55, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '다음 중 관계 대수(Relational Algebra)의 집합 연산으로 보기 어려운 것은?\n\n① UNION\n② SELECT\n③ INTERSECT\n④ MINUS', 'MCQ', 2, '정답: 2. SELECT는 관계 대수의 순수 관계 연산자이며, 집합 연산자에는 포함되지 않는다.\n\n**오답 풀이**\n- 1번: UNION은 합집합 연산이다.\n- 2번: SELECT는 조건에 맞는 튜플을 선택하는 관계 연산이다.\n- 3번: INTERSECT는 교집합 연산이다.\n- 4번: MINUS는 차집합 연산이다.\n\n**보충 개념**\n관계 대수의 집합 연산에는 합집합, 교집합, 차집합, 카티션 프로덕트 등이 포함된다.',
   '관계 대수', 2, @mock_exam_id, 56, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), 'DAS(Direct Attached Storage) 인터페이스에 사용되는 프로토콜로 보기 어려운 것은?\n\n① USB\n② SATA\n③ SCSI\n④ Fibre Channel', 'MCQ', 4, '정답: 4. Fibre Channel은 주로 SAN 환경에서 서버와 스토리지를 네트워크로 연결할 때 사용된다.\n\n**오답 풀이**\n- 1번: USB는 직접 연결 저장장치 인터페이스로 활용될 수 있다.\n- 2번: SATA는 DAS에 자주 사용되는 대표적인 인터페이스이다.\n- 3번: SCSI도 직접 연결 저장장치 인터페이스로 사용된다.\n- 4번: Fibre Channel은 주로 SAN에서 사용되는 프로토콜이다.\n\n**보충 개념**\nDAS는 서버와 저장장치를 직접 연결하는 방식이고, SAN은 별도의 스토리지 전용 네트워크를 활용한다.',
   '스토리지', 2, @mock_exam_id, 57, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '다음 중 데이터베이스 이상 현상(삽입, 갱신, 삭제 이상)의 가장 큰 원인은?\n\n① 인덱스 설정 오류\n② 데이터 중복과 종속성 문제\n③ 저장공간 부족\n④ 쿼리 최적화 실패', 'MCQ', 2, '정답: 2. 이상 현상은 테이블 설계 단계에서 데이터 중복이나 잘못된 종속성이 존재할 때 주로 발생한다.\n\n**오답 풀이**\n- 1번: 인덱스 설정 오류는 주로 성능 측면의 문제이다.\n- 2번: 데이터 중복과 종속성 문제는 이상 현상의 근본 원인이다.\n- 3번: 저장공간 부족은 이상 현상의 직접 원인이 아니다.\n- 4번: 쿼리 최적화 실패는 성능 측면의 문제이다.\n\n**보충 개념**\n정규화는 데이터의 중복과 잘못된 종속성을 줄여 이상 현상을 예방한다.',
   '이상 현상', 2, @mock_exam_id, 58, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '다음 중 STUDENT(SNO, SNAME, YEAR, DEPT) 테이블에 학번 200, 이름 김길동, 학년 2학년, 학과 전산과의 학생 정보를 삽입하는 SQL 명령으로 알맞은 것은?\n\n① INSERT INTO STUDENT (SNO, SNAME, YEAR, DEPT) VALUES (''김길동'', 200, ''2학년'', ''전산과'');\n② INSERT STUDENT (200, ''김길동'', ''2학년'', ''전산과'');\n③ INSERT INTO STUDENT VALUES (''김길동'', 200, ''2학년'', ''전산과'');\n④ INSERT INTO STUDENT (SNO, SNAME, YEAR, DEPT) VALUES (200, ''김길동'', ''2학년'', ''전산과'');', 'MCQ', 4, '정답: 4. 명시한 열 순서(SNO, SNAME, YEAR, DEPT)에 맞추어 200, 김길동, 2학년, 전산과 순으로 값을 입력해야 한다.\n\n**오답 풀이**\n- 1번: SNO 자리에 이름이 들어가 열과 값의 순서가 어긋난다.\n- 2번: INSERT INTO와 VALUES 키워드 형식이 맞지 않는다.\n- 3번: 열 목록이 없는데 값 순서가 테이블 정의와 맞지 않는다.\n- 4번: 열 순서와 값 순서가 일치하는 올바른 형식이다.\n\n**보충 개념**\nINSERT 문은 `INSERT INTO 테이블명(열목록) VALUES(값목록)` 형태로 작성한다.',
   'INSERT', 2, @mock_exam_id, 59, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '다음 중 관계대수 π name, dept (σ year = 3 (student))를 SQL로 올바르게 표현한 것은?\n\n① SELECT name, dept FROM student WHERE year = 3;\n② SELECT year FROM student WHERE name = ''dept'';\n③ SELECT * FROM student WHERE year = 3;\n④ SELECT name, dept FROM student WHERE dept = 3;', 'MCQ', 1, '정답: 1. σ year=3은 year가 3인 행을 선택하는 조건이고, π name, dept는 name과 dept 두 열만 추출하는 투영이다.\n\n**오답 풀이**\n- 1번: 조건과 추출 열이 모두 정확하다.\n- 2번: 추출 열도, 조건도 모두 잘못 표현되었다.\n- 3번: 모든 열을 조회하므로 투영 연산이 반영되지 않았다.\n- 4번: 조건이 year가 아닌 dept로 잘못 적혀 있다.\n\n**보충 개념**\n관계대수에서 σ는 선택(Select), π는 투영(Project) 연산을 의미한다.',
   '관계대수와 SQL', 2, @mock_exam_id, 60, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '다음 중 객체지향 기술의 요소로 보기 어려운 것은?\n\n① 캡슐화(Encapsulation)\n② 정보은닉(Information Hiding)\n③ 트랜잭션 제어(Transaction Control)\n④ 상속성(Inheritance)', 'MCQ', 3, '정답: 3. 트랜잭션 제어는 데이터베이스 처리 영역의 개념이며 객체지향의 기술 요소가 아니다.\n\n**오답 풀이**\n- 1번: 캡슐화는 객체지향의 핵심 특징이다.\n- 2번: 정보은닉은 객체 내부 구현을 외부로부터 가리는 객체지향 원리이다.\n- 3번: 트랜잭션 제어는 DB 트랜잭션 관리에 해당한다.\n- 4번: 상속성은 객체지향의 핵심 특징이다.\n\n**보충 개념**\n객체지향의 대표 특징에는 캡슐화, 상속, 다형성, 추상화, 정보은닉 등이 있다.',
   '객체지향', 1, @mock_exam_id, 61, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '다음 설명에 해당하는 파일 편성 방식은?\n\n**<보기>**\n레코드를 키 값 순서대로 저장하면서 인덱스를 함께 두어 순차 접근과 직접 접근을 모두 지원하는 방식이다.\n\n① 순차 파일 편성(Sequential File Organization)\n② 인덱스 순차 파일 편성(Indexed Sequential File Organization)\n③ 직접 파일 편성(Direct File Organization)\n④ 해시 파일 편성(Hash File Organization)', 'MCQ', 2, '정답: 2. 인덱스 순차 파일 편성은 키 순서로 레코드를 저장하면서 인덱스를 함께 두어 순차 접근과 직접 접근을 모두 지원한다.\n\n**오답 풀이**\n- 1번: 순차 파일 편성은 레코드를 순서대로 저장하지만, 인덱스를 통한 직접 접근을 본질적 특징으로 갖지는 않는다.\n- 2번: 인덱스 순차 파일 편성은 순차 접근과 인덱스를 통한 접근을 함께 지원한다.\n- 3번: 직접 파일 편성은 키로부터 물리적 주소를 계산해 접근한다.\n- 4번: 해시 파일 편성은 해시 함수를 이용해 저장 위치를 결정한다.\n\n**보충 개념**\n파일 편성 방식은 크게 순차, 인덱스 순차, 직접, 해시 방식 등으로 나뉜다.',
   '파일 편성', 3, @mock_exam_id, 62, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '다음 중 세마포어(Semaphore)에 대한 설명으로 가장 적절한 것은?\n\n① 프로세스 간 데이터 교환을 위한 고속 메모리 공간이다.\n② 하나의 프로세스를 여러 개의 스레드로 분할하는 기법이다.\n③ 동일한 자원에 대해 접근 권한을 명시적으로 설정하는 정책이다.\n④ 다수의 프로세스가 공유 자원에 접근할 때 상호 배제를 구현하기 위해 사용하는 동기화 기법이다.', 'MCQ', 4, '정답: 4. 세마포어는 공유 자원에 대한 동시 접근을 통제하기 위해 사용하는 동기화 기법이다.\n\n**오답 풀이**\n- 1번: 공유 메모리에 더 가까운 설명이다.\n- 2번: 멀티스레딩 분할 기법에 가까운 설명이다.\n- 3번: 접근 제어 정책에 대한 설명이다.\n- 4번: 세마포어의 정의에 부합한다.\n\n**보충 개념**\n세마포어는 P 연산과 V 연산을 사용해 임계구역에 대한 접근을 제어한다.',
   '세마포어', 2, @mock_exam_id, 63, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '다음 중 통합 개발 환경(IDE)의 세부 기능에 관한 설명으로 옳지 않은 것은?\n\n① 코드 편집 기능은 구문 강조, 자동 완성 등을 지원한다.\n② 디버깅 기능은 실행 중 오류를 찾아 수정할 수 있도록 지원한다.\n③ 형상 관리 기능은 소스 코드 버전 관리를 지원한다.\n④ 운영체제 커널을 직접 수정하는 기능을 제공한다.', 'MCQ', 4, '정답: 4. IDE는 코드 작성, 컴파일, 디버깅, 형상 관리 연동 등을 지원하지만, 운영체제 커널을 직접 수정해 주는 것을 표준 기능으로 제공하지는 않는다.\n\n**오답 풀이**\n- 1번: 코드 편집은 IDE의 기본 기능이다.\n- 2번: 디버깅 기능 제공은 IDE의 기본 기능이다.\n- 3번: 형상 관리 도구와의 연동을 지원할 수 있다.\n- 4번: 운영체제 커널의 직접 수정은 IDE의 기본 기능이 아니다.\n\n**보충 개념**\nIDE는 편집, 빌드, 실행, 디버깅 도구를 통합하여 개발 생산성을 높여 주는 환경이다.',
   'IDE', 1, @mock_exam_id, 64, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '다음 중 가비지 컬렉터(Garbage Collector)의 역할로 가장 적절한 것은?\n\n① 프로세스 간 통신을 지원한다.\n② 프로그램 실행 중 사용하지 않는 메모리를 자동으로 회수한다.\n③ 사용자 입력을 실시간으로 처리한다.\n④ 데이터베이스 연결을 최적화한다.', 'MCQ', 2, '정답: 2. 가비지 컬렉터는 더 이상 참조되지 않는 메모리 영역을 자동으로 해제하는 역할을 한다.\n\n**오답 풀이**\n- 1번: 프로세스 간 통신은 IPC와 관련된 기능이다.\n- 2번: 가비지 컬렉터의 본래 역할에 부합한다.\n- 3번: 사용자 입력 처리와는 무관하다.\n- 4번: 데이터베이스 연결 최적화와는 별개의 기능이다.\n\n**보충 개념**\n가비지 컬렉션은 메모리 누수를 줄여 주지만, 동작 시 일시적인 정지나 오버헤드가 발생할 수 있다.',
   '가비지 컬렉션', 1, @mock_exam_id, 65, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '다음 파이썬 코드의 실행 결과로 알맞은 것은?\n\n```python\ndef f(*x):\n    s = 0\n    for i in x:\n        s += i\n    return s\nprint(f(1, 2, 3))\n```\n\n① 6\n② 1 2 3\n③ 5\n④ 7', 'MCQ', 1, '정답: 1. `*x`는 가변 매개변수로 인수 1, 2, 3을 튜플 형태로 받으며, 합계 6을 반환한다.\n\n**오답 풀이**\n- 1번: 1+2+3의 결과인 6이 맞다.\n- 2번: 코드는 합계를 출력하므로 값들을 그대로 공백으로 출력하지 않는다.\n- 3번: 1+2+3은 5가 아니다.\n- 4번: 1+2+3은 7이 아니다.\n\n**보충 개념**\n파이썬의 `*args` 형태는 위치 인수들을 하나의 튜플로 묶어 받는 가변 인수 방식이다.',
   'Python 가변 인자', 2, @mock_exam_id, 66, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '다음 파이썬 코드의 실행 결과로 알맞은 것은?\n\n```python\ns = "abcd"\nfor c in s:\n    print(c, end=" ")\n```\n\n① a b c d\n② a\nb\nc\nd\n③ abcd\n④ a-b-c-d', 'MCQ', 1, '정답: 1. 문자열을 한 글자씩 순회하면서 `end=" "` 옵션 때문에 각 문자 뒤에 공백을 붙여 출력하므로 `a b c d` 형태가 된다.\n\n**오답 풀이**\n- 1번: 문자 사이에 공백이 들어간 형태로 출력된다.\n- 2번: `end`가 줄바꿈이 아닌 공백이므로 줄바꿈은 발생하지 않는다.\n- 3번: 반복마다 공백이 추가되므로 붙여서 출력되지 않는다.\n- 4번: 하이픈을 출력하라는 코드가 없다.\n\n**보충 개념**\n파이썬 `print()` 함수의 `end` 인자는 출력 끝에 붙일 문자열을 지정한다.',
   'Python 반복문', 1, @mock_exam_id, 67, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '다음 C 언어 코드의 실행 결과로 알맞은 것은?\n\n```c\n#include <stdio.h>\nint main() {\n    int b[5] = {10, 20, 30, 40, 50};\n    int a = 0;\n    printf("%d", b[(a++) + 2]);\n    return 0;\n}\n```\n\n① 10\n② 20\n③ 30\n④ 40', 'MCQ', 3, '정답: 3. `a++`는 사용 후 증가하는 후위 연산자이므로 인덱스는 0+2=2가 되고, `b[2]` 값인 30이 출력된다.\n\n**오답 풀이**\n- 1번: `b[0]` 값이 출력되는 것이 아니다.\n- 2번: `b[1]` 값이 출력되는 것이 아니다.\n- 3번: `b[2]`인 30이 정확한 출력 결과이다.\n- 4번: `b[3]` 값이 출력되는 것이 아니다.\n\n**보충 개념**\n후위 증가 연산자는 현재 값을 먼저 사용한 다음 변수의 값을 1 증가시킨다.',
   'C 증감 연산자', 2, @mock_exam_id, 68, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '다음 C 코드의 빈칸에 들어갈 적절한 printf 서식 문자 조합은?\n\n```c\n#include <stdio.h>\nint main() {\n    char a = ''X'';\n    char b = ''F'';\n    printf("<빈칸>", a, b/1.5);\n    return 0;\n}\n```\n\n① %c %d\n② %c %f\n③ %d %f\n④ %c %c', 'MCQ', 2, '정답: 2. 변수 `a`는 문자이므로 `%c`로 출력해야 하고, `b/1.5`는 실수 연산 결과이므로 `%f`가 적절하다.\n\n**오답 풀이**\n- 1번: 두 번째 값은 실수이므로 `%d`로 출력하면 의도한 결과가 나오지 않는다.\n- 2번: 문자는 `%c`, 실수는 `%f`로 출력하는 것이 알맞다.\n- 3번: 첫 번째 값은 문자 출력이 적합하므로 `%d`보다는 `%c`가 더 어울린다.\n- 4번: 두 번째 값은 실수이므로 `%c`로는 정상 출력되지 않는다.\n\n**보충 개념**\nC에서 정수와 실수 리터럴이 함께 사용된 연산은 일반적으로 double 형으로 계산된다.',
   'C 서식 지정자', 2, @mock_exam_id, 69, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '다음 C 코드의 실행 결과로 알맞은 것은?\n\n```c\n#include <stdio.h>\nint main() {\n    int a = 0x5A;\n    int b = 0x3C;\n    printf("%X", a & b);\n    return 0;\n}\n```\n\n① 1A\n② 18\n③ 5A\n④ 3C', 'MCQ', 2, '정답: 2. 0x5A와 0x3C를 비트 단위 AND 연산하면 0x18이 된다.\n\n**오답 풀이**\n- 1번: 1A는 비트 AND 결과가 아니다.\n- 2번: 0x5A & 0x3C 결과는 0x18이다.\n- 3번: 5A는 변수 a의 원래 값이다.\n- 4번: 3C는 변수 b의 원래 값이다.\n\n**보충 개념**\n비트 AND 연산은 두 비트가 모두 1일 때만 1을 결과로 만든다.',
   'C 비트 연산', 3, @mock_exam_id, 70, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '다음 C 코드의 실행 결과로 알맞은 것은?\n\n```c\n#include <stdio.h>\nint main() {\n    char a[9] = "ABACADBC";\n    for (int i = 1; i < 8; i++) {\n        if (a[i] == ''B'') {\n            a[i] = ''D'';\n        } else {\n            char t = a[i];\n            a[i] = a[i - 1];\n            a[i - 1] = t;\n        }\n    }\n    printf("%s", a);\n    return 0;\n}\n```\n\n① ADBAACDC\n② AABACDDC\n③ ABAAADCC\n④ AACADDCD', 'MCQ', 4, '정답: 4. 반복문에서 B는 D로 바꾸고, 그 외의 문자는 이전 문자와 자리를 교환하는 과정을 차례대로 적용하면 최종 문자열은 `AACADDCD`가 된다.\n\n**오답 풀이**\n- 1번: 중간 단계의 자리 교환을 잘못 추적한 결과이다.\n- 2번: B 치환과 자리 교환의 일부가 누락된 결과이다.\n- 3번: 일부 위치에서의 교환이 잘못 적용된 결과이다.\n- 4번: 반복문을 차례대로 적용한 최종 결과와 일치한다.\n\n**보충 개념**\n문자 배열을 변형하는 문제는 매 반복마다 배열 상태를 표로 정리하면서 추적하면 실수를 줄일 수 있다.',
   'C 문자열', 4, @mock_exam_id, 71, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '다음 Java 코드의 실행 결과로 알맞은 것은?\n\n```java\npublic class Main {\n    public static void main(String[] args) {\n        int a = 70;\n        int b = 50;\n        int c = ((a + b) / 2 >= 60) ? 2 : 4;\n        System.out.println(c);\n    }\n}\n```\n\n① 2\n② 4\n③ 60\n④ 120', 'MCQ', 1, '정답: 1. `(70+50)/2`의 값은 60이고 조건 `60 >= 60`이 참이므로 c에는 2가 대입되어 출력된다.\n\n**오답 풀이**\n- 1번: 조건이 참이므로 결과로 2가 출력된다.\n- 2번: 조건이 거짓일 때 사용되는 값이다.\n- 3번: 조건식의 중간 계산값일 뿐 출력 값이 아니다.\n- 4번: a+b의 값일 뿐 출력 값이 아니다.\n\n**보충 개념**\n삼항 연산자는 `조건식 ? 참일 때 값 : 거짓일 때 값` 형식으로 동작한다.',
   'Java 삼항 연산자', 1, @mock_exam_id, 72, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '다음 중 변수 명명 규칙에 어긋나는 것을 고르시오. (단, 언어는 C 또는 Java 기준이다.)\n\n① score1\n② _average\n③ 1total\n④ maxValue', 'MCQ', 3, '정답: 3. C와 Java에서 식별자는 숫자로 시작할 수 없다.\n\n**오답 풀이**\n- 1번: 영문자로 시작하고 숫자를 포함하므로 사용할 수 있다.\n- 2번: 밑줄로 시작하는 식별자는 사용할 수 있다.\n- 3번: 숫자로 시작하므로 변수명으로 사용할 수 없다.\n- 4번: 영문자로 시작하므로 사용할 수 있다.\n\n**보충 개념**\n일반적으로 변수명은 영문자 또는 밑줄로 시작할 수 있고, 숫자로 시작할 수는 없다.',
   '식별자', 1, @mock_exam_id, 73, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '다음 Java 코드는 외부에서 Account 클래스의 멤버 변수에 직접 접근하지 못하도록 접근제어자를 지정한 것이다. 빈칸에 들어갈 알맞은 접근 제어자 조합은?\n\n```java\nclass Account {\n    <빈칸> int balance;\n    <빈칸> void deposit(int amount) {\n        balance += amount;\n    }\n}\n\npublic class Main {\n    public static void main(String[] args) {\n        Account a = new Account();\n        a.deposit(100);\n    }\n}\n```\n\n① public, public\n② private, private\n③ private, public\n④ protected, public', 'MCQ', 3, '정답: 3. 외부에서 직접 접근할 수 없도록 멤버 변수는 private으로, 외부에서 호출 가능해야 하는 메서드는 public으로 선언해야 한다.\n\n**오답 풀이**\n- 1번: balance가 public이면 외부에서 직접 접근 가능해 캡슐화가 깨진다.\n- 2번: deposit까지 private이면 외부에서 호출할 수 없다.\n- 3번: balance는 private, deposit은 public이 적절한 조합이다.\n- 4번: protected는 동일 패키지나 하위 클래스에서 접근 가능하므로 외부 직접 접근 차단이 약하다.\n\n**보충 개념**\n캡슐화는 필드를 private으로 숨기고 public 메서드를 통해 통제된 접근을 허용하는 원리이다.',
   'Java 접근 제어자', 2, @mock_exam_id, 74, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), 'Java에서 A 클래스의 생성자 이름과, 과거에 소멸자와 유사한 역할로 설명되었던 메소드 이름의 조합으로 가장 적절한 것은?\n\n① 생성자: A, 소멸자: finalize\n② 생성자: init, 소멸자: delete\n③ 생성자: A, 소멸자: destructor\n④ 생성자: newA, 소멸자: destroy', 'MCQ', 1, '정답: 1. Java의 생성자 이름은 클래스명과 같아야 하므로 A 클래스의 생성자는 A이다. Java에는 C++와 같은 명시적 소멸자가 존재하지 않지만, 과거에는 `finalize` 메소드가 소멸자와 유사한 역할로 설명되었다.\n\n**오답 풀이**\n- 1번: 생성자 이름은 클래스명 A와 같으며, finalize는 과거 소멸자 유사 메소드로 설명되었다.\n- 2번: init과 delete는 Java의 생성자·소멸자 이름이 아니다.\n- 3번: destructor는 Java의 소멸자 메소드 이름이 아니다.\n- 4번: newA와 destroy는 Java의 생성자·소멸자 이름이 아니다.\n\n**보충 개념**\nJava는 명시적인 소멸자를 따로 두지 않으며, 객체 메모리는 가비지 컬렉터가 자동으로 회수한다.',
   'Java 생성자', 2, @mock_exam_id, 75, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '다음 중 페이징(Paging) 기법에 대한 설명으로 옳지 않은 것은?\n\n① 주기억장치를 동일한 크기의 페이지 단위로 나눈다.\n② 가상 주소를 페이지 번호와 페이지 내 주소로 구분하여 관리한다.\n③ 프로세스 전체를 연속된 공간에 적재해야만 실행할 수 있다.\n④ 페이지 단위로 메모리를 관리하여 단편화를 줄일 수 있다.', 'MCQ', 3, '정답: 3. 페이징은 프로세스를 동일 크기의 페이지로 나누어 메모리에 비연속적으로 배치할 수 있게 해 주는 기법이다.\n\n**오답 풀이**\n- 1번: 페이징은 메모리를 동일 크기의 단위로 나누어 사용한다.\n- 2번: 가상 주소는 페이지 번호와 페이지 내 변위로 구분된다.\n- 3번: 프로세스 전체를 반드시 연속된 공간에 적재해야 하는 것은 아니다.\n- 4번: 페이징은 외부 단편화 문제를 줄이는 데 효과적이다.\n\n**보충 개념**\n페이징은 프로세스를 여러 페이지로 나누고 페이지 테이블을 활용해 주소 변환을 수행한다.',
   '페이징', 2, @mock_exam_id, 76, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '다음 중 리피터(Repeater)에 대한 설명으로 옳지 않은 것은?\n\n① 신호를 증폭하여 전송 거리를 연장한다.\n② 1계층(물리 계층)에서 동작한다.\n③ 신호를 수신하고 재생하여 다시 송신한다.\n④ 패킷을 분석하여 최적 경로를 선택한다.', 'MCQ', 4, '정답: 4. 패킷을 분석하여 최적 경로를 결정하는 장비는 리피터가 아닌 라우터이다.\n\n**오답 풀이**\n- 1번: 리피터는 약해진 신호를 증폭해 전송 거리를 늘려 준다.\n- 2번: 리피터는 OSI 1계층(물리 계층)에서 동작한다.\n- 3번: 리피터는 신호를 받아 재생한 뒤 다시 송신한다.\n- 4번: 경로 선택은 라우터가 수행한다.\n\n**보충 개념**\n리피터는 물리 계층에서 전기적 신호를 재생하는 단순한 네트워크 장비이다.',
   '리피터', 1, @mock_exam_id, 77, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '다음 중 First Fit 메모리 할당 기법에 대한 설명으로 가장 적절한 것은?\n\n① 가장 큰 빈 공간을 찾아 할당하는 기법이다.\n② 메모리에서 처음으로 발견된 충분한 크기의 빈 공간에 데이터를 할당하는 기법이다.\n③ 가장 작은 빈 공간을 찾아 할당하는 기법이다.\n④ 메모리 전체를 탐색하여 최적의 공간을 찾는 기법이다.', 'MCQ', 2, '정답: 2. First Fit은 빈 공간을 처음부터 차례로 검색하다가 요청 크기보다 크거나 같은 첫 번째 공간을 만나면 그곳에 할당한다.\n\n**오답 풀이**\n- 1번: 가장 큰 빈 공간을 선택하는 방식은 Worst Fit이다.\n- 2번: 첫 번째로 발견된 충분한 공간에 할당하는 방식이 First Fit이다.\n- 3번: 가장 작은 적합 공간을 선택하는 방식은 Best Fit이다.\n- 4번: 전체를 모두 탐색해 최적 공간을 고르는 방식은 Best Fit에 가깝다.\n\n**보충 개념**\n연속 메모리 할당 기법에는 First Fit, Best Fit, Worst Fit 등이 있다.',
   '메모리 할당', 1, @mock_exam_id, 78, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), 'umask 값이 022로 설정되어 있을 때, 새로 생성되는 일반 파일의 기본 권한 666에서 other에게서 제거되는 권한은?\n\n① 읽기(Read)\n② 쓰기(Write)\n③ 실행(Execute)\n④ 읽기와 실행(Read and Execute)', 'MCQ', 2, '정답: 2. 일반 파일의 기본 권한 666에 umask 022를 적용하면 644가 된다. other 부분은 6에서 2가 빠져 4(읽기)만 남으므로, 결과적으로 쓰기 권한이 제거된다.\n\n**오답 풀이**\n- 1번: 적용 후 other에게도 읽기 권한은 그대로 남는다.\n- 2번: other의 쓰기 권한이 umask 적용으로 제거된다.\n- 3번: 일반 파일의 기본 권한 666에는 처음부터 실행 권한이 포함되지 않는다.\n- 4번: other에게 실행 권한이 함께 제거되는 것은 아니다.\n\n**보충 개념**\numask는 새 파일이나 디렉터리를 만들 때 기본 권한에서 빼고 시작할 권한을 정의한다.',
   'umask', 3, @mock_exam_id, 79, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '다음 중 디자인 패턴의 분류에 해당하지 않는 것은?\n\n① 생성 패턴(Creational Pattern)\n② 구조 패턴(Structural Pattern)\n③ 동기화 패턴(Synchronization Pattern)\n④ 행동 패턴(Behavioral Pattern)', 'MCQ', 3, '정답: 3. GoF 디자인 패턴은 생성 패턴, 구조 패턴, 행위(행동) 패턴의 세 가지로 분류된다.\n\n**오답 풀이**\n- 1번: 생성 패턴은 GoF 디자인 패턴 분류 중 하나이다.\n- 2번: 구조 패턴은 GoF 디자인 패턴 분류 중 하나이다.\n- 3번: 동기화 패턴은 GoF 디자인 패턴의 기본 분류에 해당하지 않는다.\n- 4번: 행동 패턴은 GoF 디자인 패턴 분류 중 하나이다.\n\n**보충 개념**\n디자인 패턴은 자주 등장하는 설계 문제에 대해 검증된 해법을 정리한 것이다.',
   '디자인 패턴', 1, @mock_exam_id, 80, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '다음 중 오용 탐지(Misuse Detection)에 대한 설명으로 옳지 않은 것은?\n\n① 정상 행위를 기준으로 이상 징후를 탐지하는 방법이다.\n② 알려진 공격 패턴을 기반으로 시스템 침입을 탐지한다.\n③ 오용에 해당하는 패턴을 정의하여 탐지 정확도를 높인다.\n④ 서명 기반 탐지 방법과 밀접하게 연관된다.', 'MCQ', 1, '정답: 1. 정상 행위를 기준으로 이상 징후를 잡아내는 방식은 이상 탐지(Anomaly Detection)에 해당한다.\n\n**오답 풀이**\n- 1번: 이상 탐지에 대한 설명에 해당한다.\n- 2번: 오용 탐지는 알려진 공격 패턴을 기반으로 한다.\n- 3번: 오용 탐지는 공격 패턴을 정의하여 정확도를 높인다.\n- 4번: 서명 기반 탐지와 밀접한 관련이 있다.\n\n**보충 개념**\n오용 탐지는 알려진 공격 탐지에는 강하지만, 새로운 공격을 잡아내는 데에는 한계가 있다.',
   '침입 탐지', 2, @mock_exam_id, 81, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '다음 중 암호 기술과 직접적인 관련이 없는 것은?\n\n① 대칭 키 암호화\n② 공개 키 기반구조(PKI)\n③ 해시 함수\n④ 라운드 로빈 스케줄링', 'MCQ', 4, '정답: 4. 라운드 로빈 스케줄링은 운영체제의 CPU 스케줄링 기법이며 암호 기술과는 직접적인 관련이 없다.\n\n**오답 풀이**\n- 1번: 대칭 키 암호화는 대표적인 암호 기술이다.\n- 2번: PKI는 공개키 암호 기반의 인증 인프라이다.\n- 3번: 해시 함수는 무결성 검증 등 암호 분야에서 폭넓게 사용된다.\n- 4번: 라운드 로빈 스케줄링은 CPU 스케줄링 방식이다.\n\n**보충 개념**\n암호 기술에는 대칭키 암호, 공개키 암호, 해시 함수, 전자서명, 인증서 등이 포함된다.',
   '암호 기술', 1, @mock_exam_id, 82, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '공개 키 암호 방식 중 두 개의 큰 소수의 곱셈을 기반으로 키를 만들고, 암호화와 복호화에 서로 다른 키를 사용하는 대표적인 비대칭 암호 알고리즘은?\n\n① AES\n② DES\n③ RSA\n④ SHA-256', 'MCQ', 3, '정답: 3. RSA는 큰 수의 소인수분해 어려움에 기반한 대표적인 공개키 암호 방식이다.\n\n**오답 풀이**\n- 1번: AES는 대칭키 블록 암호 알고리즘이다.\n- 2번: DES는 대칭키 블록 암호 알고리즘이다.\n- 3번: RSA는 대표적인 공개키 암호 방식이다.\n- 4번: SHA-256은 해시 알고리즘이다.\n\n**보충 개념**\n공개키 암호는 암호화와 복호화에 서로 다른 키 쌍을 사용하는 비대칭 방식이다.',
   'RSA', 1, @mock_exam_id, 83, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '다음 중 세션 하이재킹(Session Hijacking) 탐지나 방어 기법으로 보기 어려운 것은?\n\n① 세션 키 주기적 변경\n② 사용자 행위 패턴 분석\n③ IP 주소 및 User-Agent 검사\n④ 암호화되지 않은 비밀번호 저장', 'MCQ', 4, '정답: 4. 비밀번호를 암호화하지 않은 채 저장하는 것은 그 자체가 보안 위협 요소이며 세션 하이재킹 탐지·방어 기법이 아니다.\n\n**오답 풀이**\n- 1번: 세션 키를 주기적으로 변경하면 세션 탈취 위험이 줄어든다.\n- 2번: 사용자 행위 패턴 분석은 이상 징후 탐지에 활용된다.\n- 3번: IP 주소와 User-Agent 검사는 세션 도용 여부를 판단하는 데 사용될 수 있다.\n- 4번: 평문 비밀번호 저장은 부적절한 보안 관행이다.\n\n**보충 개념**\n세션 하이재킹은 공격자가 정상적으로 발급된 세션을 탈취해 사용자처럼 시스템에 접근하는 공격이다.',
   '세션 하이재킹', 2, @mock_exam_id, 84, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '다음 중 거리 벡터(Distance Vector) 라우팅 방식을 사용하며 최대 홉 수가 15로 제한되는 라우팅 프로토콜은?\n\n① OSPF\n② BGP\n③ RIP\n④ IS-IS', 'MCQ', 3, '정답: 3. RIP는 거리 벡터 방식의 라우팅 프로토콜이며 최대 홉 수가 15로 제한된다.\n\n**오답 풀이**\n- 1번: OSPF는 링크 상태 라우팅 프로토콜이다.\n- 2번: BGP는 경로 벡터 방식의 외부 게이트웨이 프로토콜이다.\n- 3번: RIP는 거리 벡터 라우팅 프로토콜이며 최대 홉 수가 15이다.\n- 4번: IS-IS는 링크 상태 라우팅 프로토콜이다.\n\n**보충 개념**\nRIP는 구성과 사용이 단순하지만 대규모 네트워크에는 적합하지 않다.',
   'RIP', 2, @mock_exam_id, 85, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '다음 중 HRN(Highest Response Ratio Next) 스케줄링 기법에서 우선순위를 계산하는 공식으로 가장 적절한 것은?\n\n① (대기 시간 + 서비스 시간) ÷ 서비스 시간\n② (도착 시간 + 서비스 시간) ÷ 대기 시간\n③ 서비스 시간 + 대기 시간\n④ 도착 시간 + 서비스 시간', 'MCQ', 1, '정답: 1. HRN의 우선순위는 `(대기 시간 + 서비스 시간) / 서비스 시간` 공식으로 계산한다.\n\n**오답 풀이**\n- 1번: HRN의 우선순위 공식과 일치한다.\n- 2번: 도착 시간을 사용하는 공식이 아니다.\n- 3번: 단순 합이 아니라 서비스 시간으로 나누어야 한다.\n- 4번: 도착 시간과 서비스 시간의 합으로는 우선순위가 산출되지 않는다.\n\n**보충 개념**\nHRN은 짧은 작업을 우선시하는 SJF의 단점인 긴 작업의 기아 현상을 완화하기 위한 방식이다.',
   'HRN', 1, @mock_exam_id, 86, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '다음 중 WEP의 취약점을 보완하기 위해 등장한 무선 네트워크 보안 프로토콜은?\n\n① WPA\n② TKIP\n③ AES\n④ SSL', 'MCQ', 1, '정답: 1. WPA는 WEP의 보안상 한계를 개선하기 위해 만들어진 무선 네트워크 보안 규격이다.\n\n**오답 풀이**\n- 1번: WPA는 WEP의 취약점을 보완하기 위해 등장한 무선 보안 규격이다.\n- 2번: TKIP는 WPA에서 사용된 암호화 방식 중 하나이지만, 문항이 묻는 “무선 네트워크 보안 프로토콜”로는 WPA가 더 적절하다.\n- 3번: AES는 대칭키 블록 암호 알고리즘이다.\n- 4번: SSL은 전송 계층의 보안 프로토콜이다.\n\n**보충 개념**\nWEP의 보안 취약점을 보완하기 위해 WPA가 등장했고, 이후 WPA2와 WPA3로 발전했다.',
   '무선 보안', 2, @mock_exam_id, 87, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '다음 중 VLAN(Virtual LAN)에 대한 설명으로 가장 적절한 것은?\n\n① 하나의 물리적 네트워크를 여러 개의 가상 네트워크로 분리하는 기술이다.\n② 서로 다른 물리적 네트워크를 하나로 통합하는 기술이다.\n③ 인터넷 접속 속도를 향상시키는 기술이다.\n④ IP 주소를 자동으로 할당하는 기술이다.', 'MCQ', 1, '정답: 1. VLAN은 하나의 물리적 네트워크를 논리적으로 여러 개의 가상 네트워크로 나누는 기술이다.\n\n**오답 풀이**\n- 1번: VLAN의 정의에 부합한다.\n- 2번: 서로 다른 물리 네트워크를 하나로 합치는 기술이 아니다.\n- 3번: 인터넷 접속 속도를 직접 향상시키는 기술이 아니다.\n- 4번: IP 자동 할당은 DHCP의 역할이다.\n\n**보충 개념**\nVLAN은 브로드캐스트 도메인을 분리하여 보안성과 관리 효율을 함께 높여 준다.',
   'VLAN', 1, @mock_exam_id, 88, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '다음 중 OSI 7계층에서 네트워크 계층(Network Layer)의 주요 기능으로 보기 어려운 것은?\n\n① 경로 선택(Routing)\n② 패킷 전달(Packet Forwarding)\n③ 흐름 제어(Flow Control)\n④ 논리적 주소(IP 주소) 할당', 'MCQ', 3, '정답: 3. 흐름 제어는 일반적으로 전송 계층에서 담당하는 기능이다.\n\n**오답 풀이**\n- 1번: 경로 선택은 네트워크 계층의 주요 기능이다.\n- 2번: 패킷 전달은 네트워크 계층의 주요 기능이다.\n- 3번: 흐름 제어는 전송 계층의 기능에 해당한다.\n- 4번: IP 주소 기반의 논리 주소 할당은 네트워크 계층의 기능이다.\n\n**보충 개념**\n네트워크 계층은 IP 주소를 기반으로 패킷의 경로를 결정하고 전달하는 역할을 수행한다.',
   'OSI 7계층', 2, @mock_exam_id, 89, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '다음 중 ARP(Address Resolution Protocol)에 대한 설명으로 옳지 않은 것은?\n\n① IP 주소를 MAC 주소로 변환해주는 프로토콜이다.\n② 네트워크 계층에서 동작하는 프로토콜이다.\n③ 같은 네트워크 안에서 호스트 정보를 탐색한다.\n④ MAC 주소를 IP 주소로 변환하는 역할을 한다.', 'MCQ', 4, '정답: 4. MAC 주소를 IP 주소로 변환하는 역할을 하는 것은 ARP가 아닌 RARP이다.\n\n**오답 풀이**\n- 1번: ARP는 IP 주소를 MAC 주소로 변환하는 프로토콜이다.\n- 2번: ARP는 네트워크 계층과 데이터링크 계층 사이에서 주소 해석을 담당한다.\n- 3번: 같은 네트워크 내에서 MAC 주소를 찾기 위해 사용된다.\n- 4번: MAC 주소를 IP 주소로 변환하는 역할은 RARP가 수행한다.\n\n**보충 개념**\nARP 요청은 브로드캐스트로 전송되며, 대상 호스트가 자신의 MAC 주소로 응답한다.',
   'ARP', 2, @mock_exam_id, 90, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '다음 중 IPv4의 특징으로 보기 어려운 것은?\n\n① 32비트 주소 체계를 사용한다.\n② 주소 고갈 문제를 해결하기 위해 설계되었다.\n③ 4개의 옥텟(Octet)으로 구성된다.\n④ 네트워크 계층에서 동작한다.', 'MCQ', 2, '정답: 2. 주소 고갈 문제를 해결하기 위해 설계된 것은 IPv4가 아닌 IPv6이다.\n\n**오답 풀이**\n- 1번: IPv4는 32비트 주소 체계를 사용한다.\n- 2번: 주소 고갈 해결을 목적으로 설계된 프로토콜은 IPv6이다.\n- 3번: IPv4 주소는 8비트씩 4개의 옥텟으로 구성된다.\n- 4번: IP는 네트워크 계층에서 동작하는 프로토콜이다.\n\n**보충 개념**\nIPv6는 128비트 주소 체계를 채택해 IPv4의 주소 고갈 문제를 해결한다.',
   'IPv4', 1, @mock_exam_id, 91, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '다음 중 블록체인 네트워크의 구축, 운영, 관리 기능을 클라우드 서비스 형태로 제공하는 것은?\n\n① SaaS\n② PaaS\n③ FaaS\n④ BaaS', 'MCQ', 4, '정답: 4. BaaS(Blockchain as a Service)는 블록체인 네트워크의 구축과 운영을 클라우드 형태로 제공하는 서비스 모델이다.\n\n**오답 풀이**\n- 1번: SaaS는 소프트웨어 기능 자체를 서비스로 제공하는 모델이다.\n- 2번: PaaS는 개발 플랫폼을 서비스로 제공한다.\n- 3번: FaaS는 함수 단위 실행을 서비스로 제공하는 서버리스 모델이다.\n- 4번: BaaS는 블록체인 인프라와 관련 서비스를 제공한다.\n\n**보충 개념**\nBaaS를 활용하면 블록체인 인프라 구축 부담을 덜고 애플리케이션 개발에 집중할 수 있다.',
   'BaaS', 1, @mock_exam_id, 92, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '다음 설명에 해당하는 것은?\n\n**<보기>**\nIBM에서 개발한 고가용성 클러스터링 솔루션으로 시스템이나 서버 장애 발생 시 다른 시스템이 자동으로 서비스를 이어받아 무중단 서비스를 지원하는 기능을 제공한다.\n\n① Memristor\n② HACMP\n③ VMware\n④ Docker', 'MCQ', 2, '정답: 2. HACMP는 IBM이 개발한 고가용성 클러스터링 솔루션이다.\n\n**오답 풀이**\n- 1번: Memristor는 전기 회로 소자에 해당한다.\n- 2번: HACMP는 IBM의 고가용성 클러스터링 솔루션이다.\n- 3번: VMware는 가상화 솔루션이다.\n- 4번: Docker는 컨테이너 기술이다.\n\n**보충 개념**\n고가용성 클러스터는 장애가 발생했을 때 서비스를 다른 노드로 자동 전환해 중단 시간을 최소화한다.',
   'HACMP', 2, @mock_exam_id, 93, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '다음 중 허니팟(Honeypot)에 대한 설명으로 옳지 않은 것은?\n\n① 공격자를 유인하기 위해 의도적으로 취약한 시스템을 구축하는 것이다.\n② 공격자의 침입 경로와 공격 방법을 분석할 수 있다.\n③ 보안 시스템을 강화하기 위해 공격자의 접근을 완전히 차단하는 기술이다.\n④ 실제 운영 시스템과 분리되어 별도로 구축된다.', 'MCQ', 3, '정답: 3. 허니팟은 공격을 차단하기 위한 기술이 아니라, 공격자를 끌어들여 그 행위를 분석하기 위한 시스템이다.\n\n**오답 풀이**\n- 1번: 허니팟은 의도적으로 취약하게 보이는 시스템처럼 구성된다.\n- 2번: 공격자의 침입 경로와 행위를 분석할 수 있다.\n- 3번: 접근을 완전히 차단하는 기술이 아니다.\n- 4번: 보통 실제 운영 시스템과 분리하여 별도로 구축한다.\n\n**보충 개념**\n허니팟은 공격 기법을 수집하고 보안 정책 개선에 활용하는 데 효과적이다.',
   '허니팟', 1, @mock_exam_id, 94, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '다음 중 사용자가 주장하는 신원이 실제와 일치하는지를 시스템이 검증하는 절차를 의미하는 것은?\n\n① Authorization\n② Accounting\n③ Auditing\n④ Authentication', 'MCQ', 4, '정답: 4. 사용자가 주장한 신원의 진위를 확인하는 절차를 인증(Authentication)이라 한다.\n\n**오답 풀이**\n- 1번: Authorization은 인증된 사용자에게 권한을 부여하는 인가 과정이다.\n- 2번: Accounting은 사용자의 활동 내역을 기록·관리하는 과정이다.\n- 3번: Auditing은 시스템 활동을 감사하는 과정이다.\n- 4번: Authentication은 신원 검증 절차에 해당한다.\n\n**보충 개념**\nAAA는 Authentication, Authorization, Accounting의 머리글자로 정보보호의 기본 절차를 가리킨다.',
   '인증', 1, @mock_exam_id, 95, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '다음 중 “something you have” 인증 요소로 보기 어려운 것은?\n\n① OTP 토큰\n② 스마트 카드\n③ 지문 인식\n④ 보안 카드', 'MCQ', 3, '정답: 3. 지문 인식은 사용자의 신체적 특성을 이용하므로 “something you are” 범주에 속한다.\n\n**오답 풀이**\n- 1번: OTP 토큰은 소유 기반 인증 요소이다.\n- 2번: 스마트 카드는 소유 기반 인증 요소이다.\n- 3번: 지문 인식은 존재(생체) 기반 인증 요소에 해당한다.\n- 4번: 보안 카드는 소유 기반 인증 요소이다.\n\n**보충 개념**\n인증 요소는 일반적으로 지식 기반, 소유 기반, 존재 기반의 세 범주로 구분된다.',
   '인증 요소', 1, @mock_exam_id, 96, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '다음 중 공개키 암호화 기법으로 보기 어려운 것은?\n\n① RSA\n② ElGamal\n③ AES\n④ ECC', 'MCQ', 3, '정답: 3. AES는 대칭키 블록 암호 알고리즘이며 공개키 암호화 기법이 아니다.\n\n**오답 풀이**\n- 1번: RSA는 공개키 암호화 알고리즘이다.\n- 2번: ElGamal은 공개키 암호화 알고리즘이다.\n- 3번: AES는 대칭키 암호화 알고리즘이다.\n- 4번: ECC는 타원곡선을 이용한 공개키 암호화 알고리즘이다.\n\n**보충 개념**\n공개키 암호는 공개키와 개인키를 분리해 사용하는 반면, 대칭키 암호는 같은 키로 암호화와 복호화를 수행한다.',
   '공개키 암호', 1, @mock_exam_id, 97, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '다음 중 Beacon에 대한 설명으로 가장 적절한 것은?\n\n① 블루투스 통신을 이용해 주변 기기에 주기적으로 신호를 전송하는 장치이다.\n② 근거리 무선통신 방식으로 데이터를 직접 전송하는 장치이다.\n③ 고속 데이터 전송을 위해 사용하는 광대역 무선 장치이다.\n④ 장거리 통신을 지원하는 위성 통신 장치이다.', 'MCQ', 1, '정답: 1. Beacon은 블루투스를 기반으로 주변 기기에 주기적으로 신호를 송출하는 장치이다.\n\n**오답 풀이**\n- 1번: Beacon의 정의에 부합한다.\n- 2번: NFC와 같은 근거리 직접 데이터 전송 방식에 더 가까운 설명이다.\n- 3번: 광대역 무선 전송 장치에 대한 설명이다.\n- 4번: 위성 통신 장치에 대한 설명이다.\n\n**보충 개념**\nBeacon은 BLE를 기반으로 위치 기반 서비스, 매장 안내, 근접 알림 등에 활용된다.',
   'Beacon', 1, @mock_exam_id, 98, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '다음 중 위치 기반 서비스를 제공하는 소셜 네트워크 애플리케이션으로, 사용자가 방문한 장소를 체크인하고 이를 공유할 수 있게 해 주는 서비스는?\n\n① Foursquare\n② WhatsApp\n③ Zoom\n④ Spotify', 'MCQ', 1, '정답: 1. Foursquare는 위치 기반의 체크인과 장소 공유 기능을 제공하는 서비스이다.\n\n**오답 풀이**\n- 1번: Foursquare는 위치 기반 소셜 네트워크 서비스이다.\n- 2번: WhatsApp은 메신저 서비스이다.\n- 3번: Zoom은 화상회의 서비스이다.\n- 4번: Spotify는 음악 스트리밍 서비스이다.\n\n**보충 개념**\n위치 기반 서비스는 사용자의 위치 정보를 활용해 주변 장소 추천, 체크인, 광고 등 다양한 기능을 제공한다.',
   '위치 기반 서비스', 1, @mock_exam_id, 99, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '다음 중 정보보안 3요소(CIA)에 포함되지 않는 것은?\n\n① 기밀성(Confidentiality)\n② 무결성(Integrity)\n③ 가용성(Availability)\n④ 정확성(Accuracy)', 'MCQ', 4, '정답: 4. 정보보안의 3요소는 기밀성, 무결성, 가용성이며 정확성은 포함되지 않는다.\n\n**오답 풀이**\n- 1번: 기밀성은 CIA의 C에 해당한다.\n- 2번: 무결성은 CIA의 I에 해당한다.\n- 3번: 가용성은 CIA의 A에 해당한다.\n- 4번: 정확성은 정보보안 3요소에 포함되지 않는다.\n\n**보충 개념**\nCIA는 Confidentiality, Integrity, Availability의 약어로 정보보안의 기본 목표를 의미한다.',
   '정보보안 3요소', 1, @mock_exam_id, 100, 'NONE', NULL, NOW(6), NOW(6))
;